import { GoogleGenAI, Type } from "@google/genai";
import { DesignStrategy } from "../types";

if (!process.env.API_KEY) {
  console.error("Missing API_KEY in environment variables.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateDesignStrategy = async (
  slogan: string, 
  niche: string, 
  styleContext: string,
  targetAudience: string,
  colorContext: string
): Promise<DesignStrategy> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are a world-class Print-on-Demand (POD) Strategist. 
      Analyze the slogan: "${slogan}" for the niche: "${niche}".
      Target Audience: ${targetAudience || 'General public'}.
      Required Style: ${styleContext}.
      Required Color Palette: ${colorContext}.

      Goal: Create a design strategy that is commercially viral on platforms like Redbubble, Etsy, and Amazon Merch.

      Requirements:
      1. Design Style: Define typography that is legible and trendy. Suggest an art style that fits the audience. Use the color palette provided.
      2. Mockups: Suggest environments where the target audience would actually use these products.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            designStyle: {
              type: Type.OBJECT,
              properties: {
                typography: { type: Type.STRING },
                artStyle: { type: Type.STRING },
                colors: { type: Type.STRING },
                mood: { type: Type.STRING },
              },
              required: ["typography", "artStyle", "colors", "mood"]
            },
            mockups: {
              type: Type.OBJECT,
              properties: {
                tshirt: {
                  type: Type.OBJECT,
                  properties: {
                    model: { type: Type.STRING },
                    environment: { type: Type.STRING },
                    lighting: { type: Type.STRING },
                  }
                },
                mug: {
                  type: Type.OBJECT,
                  properties: {
                    setting: { type: Type.STRING },
                    props: { type: Type.STRING },
                  }
                },
                sticker: {
                  type: Type.OBJECT,
                  properties: {
                    surface: { type: Type.STRING },
                    lighting: { type: Type.STRING },
                  }
                },
                phoneCase: {
                  type: Type.OBJECT,
                  properties: {
                    surface: { type: Type.STRING },
                    props: { type: Type.STRING },
                  }
                },
                composite: {
                  type: Type.OBJECT,
                  properties: {
                    arrangement: { type: Type.STRING },
                    theme: { type: Type.STRING },
                  }
                },
              }
            }
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as DesignStrategy;
    }
    throw new Error("No strategy generated");
  } catch (error) {
    console.error("Error generating strategy:", error);
    return {
      designStyle: { typography: "Bold Sans-serif", artStyle: "Minimalist", colors: "Modern Palette", mood: "Professional" },
      mockups: {
        tshirt: { model: "Model", environment: "Studio", lighting: "Soft" },
        mug: { setting: "Table", props: "None" },
        sticker: { surface: "Laptop", lighting: "Natural" },
        phoneCase: { surface: "Desk", props: "None" },
        composite: { arrangement: "Flat-lay", theme: "Unified" }
      }
    };
  }
};

export const generateMockupImage = async (prompt: string, referenceImageBase64?: string | null): Promise<string> => {
  try {
    const parts: any[] = [{ text: prompt }];
    if (referenceImageBase64) {
      const base64Data = referenceImageBase64.replace(/^data:image\/\w+;base64,/, "");
      parts.push({
        inlineData: {
          mimeType: 'image/png',
          data: base64Data
        }
      });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: parts },
      config: {
        imageConfig: { aspectRatio: "1:1" }
      }
    });

    const candidates = response.candidates;
    if (!candidates || candidates.length === 0) throw new Error("No image generated.");

    const imagePart = candidates[0].content.parts.find(p => p.inlineData);
    if (!imagePart?.inlineData?.data) throw new Error("Missing image data.");

    return `data:image/png;base64,${imagePart.inlineData.data}`;
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Wand2, Loader2, Sparkles, PenTool, Paintbrush, Users, Palette } from 'lucide-react';
import { NICHES, DESIGN_STYLES, COLOR_PALETTES } from '../constants';

interface PromptInputProps {
  onGenerate: (slogan: string, niche: string, styleContext: string, audience: string, colorContext: string) => void;
  isGenerating: boolean;
  statusText?: string;
}

const PromptInput: React.FC<PromptInputProps> = ({ onGenerate, isGenerating, statusText }) => {
  const [slogan, setSlogan] = useState('');
  const [selectedNicheId, setSelectedNicheId] = useState(NICHES[0].id);
  const [customNiche, setCustomNiche] = useState('');
  const [selectedStyleId, setSelectedStyleId] = useState(DESIGN_STYLES[0].id);
  const [selectedColorId, setSelectedColorId] = useState(COLOR_PALETTES[0].id);
  const [audience, setAudience] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalNiche = '';
    if (selectedNicheId === 'custom') {
        finalNiche = customNiche.trim();
    } else {
        const nicheObj = NICHES.find(n => n.id === selectedNicheId);
        finalNiche = nicheObj ? nicheObj.label : selectedNicheId;
    }

    const styleObj = DESIGN_STYLES.find(s => s.id === selectedStyleId) || DESIGN_STYLES[0];
    const colorObj = COLOR_PALETTES.find(c => c.id === selectedColorId) || COLOR_PALETTES[0];

    if (slogan.trim() && finalNiche) {
      onGenerate(slogan, finalNiche, styleObj.context, audience, colorObj.context);
    }
  };

  const isCustomNiche = selectedNicheId === 'custom';

  return (
    <div className="w-full max-w-5xl mx-auto -mt-6 relative z-10 px-4">
      <form onSubmit={handleSubmit} className="bg-slate-800 p-6 rounded-2xl shadow-2xl border border-slate-700 flex flex-col gap-5">

        {/* Row 1: Primary Selectors */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {/* Niche & Custom */}
            <div className="flex flex-col gap-3">
                <div className="relative">
                  <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Target Niche</label>
                  <select
                    value={selectedNicheId}
                    onChange={(e) => setSelectedNicheId(e.target.value)}
                    className="w-full appearance-none bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm pr-10"
                    disabled={isGenerating}
                  >
                    {NICHES.map((n) => (
                        <option key={n.id} value={n.id}>{n.label}</option>
                    ))}
                  </select>
                  <Sparkles className="absolute right-3 top-[34px] w-4 h-4 text-slate-500 pointer-events-none" />
                </div>
                {isCustomNiche && (
                    <input
                        type="text"
                        value={customNiche}
                        onChange={(e) => setCustomNiche(e.target.value)}
                        placeholder="Type niche..."
                        className="w-full bg-slate-900 text-white px-4 py-3 rounded-xl border border-indigo-500/50 focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
                        disabled={isGenerating}
                    />
                )}
            </div>

            {/* Style Selector */}
            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Visual Trend</label>
                <select
                    value={selectedStyleId}
                    onChange={(e) => setSelectedStyleId(e.target.value)}
                    className="w-full appearance-none bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm pr-10"
                    disabled={isGenerating}
                >
                    {DESIGN_STYLES.map((s) => (
                        <option key={s.id} value={s.id}>{s.label}</option>
                    ))}
                </select>
                <Paintbrush className="absolute right-3 top-10 w-4 h-4 text-slate-500 pointer-events-none" />
            </div>

            {/* Color Palette Selector */}
            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Color Palette</label>
                <div className="grid grid-cols-3 gap-2">
                    {COLOR_PALETTES.map((cp) => (
                        <button
                            key={cp.id}
                            type="button"
                            onClick={() => setSelectedColorId(cp.id)}
                            className={`p-1 rounded-lg border transition-all ${selectedColorId === cp.id ? 'border-indigo-500 bg-indigo-500/10' : 'border-slate-700 bg-slate-900 hover:border-slate-500'}`}
                            title={cp.label}
                        >
                            <div className="flex gap-0.5 mb-1 justify-center">
                                {cp.colors.map((c, i) => (
                                    <div key={i} className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: c }} />
                                ))}
                            </div>
                            <span className="text-[10px] text-slate-400 block truncate">{cp.label}</span>
                        </button>
                    ))}
                </div>
            </div>
        </div>

        {/* Row 2: Audience & Slogan */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Who is this for? (Audience)</label>
                <div className="relative">
                    <input
                        type="text"
                        value={audience}
                        onChange={(e) => setAudience(e.target.value)}
                        placeholder="e.g., Cat Lovers, Proud Teachers, Gen Z..."
                        className="w-full bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm pl-10"
                        disabled={isGenerating}
                    />
                    <Users className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                </div>
            </div>

            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Slogan / Text on Shirt</label>
                <input
                    type="text"
                    value={slogan}
                    onChange={(e) => setSlogan(e.target.value)}
                    placeholder="e.g., 'Not all who wander are lost'"
                    className="w-full bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-medium"
                    disabled={isGenerating}
                />
            </div>
        </div>

        {/* Submit Button */}
        <button
          type="submit"
          disabled={isGenerating || !slogan.trim()}
          className="w-full bg-gradient-to-r from-indigo-600 to-indigo-500 hover:from-indigo-500 hover:to-indigo-400 text-white font-bold px-8 py-4 rounded-xl transition-all shadow-lg shadow-indigo-500/30 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
        >
          {isGenerating ? (
            <>
              <Loader2 className="w-5 h-5 animate-spin" />
              <span>{statusText || 'Brainstorming Market Strategy...'}</span>
            </>
          ) : (
            <>
              <Wand2 className="w-5 h-5" />
              <span>Generate Viral Design & Mockups</span>
            </>
          )}
        </button>
      </form>
      <div className="text-center mt-4 text-slate-500 text-xs flex items-center justify-center gap-4">
        <span className="flex items-center gap-1"><BrainCircuit className="w-3 h-3" /> Strategy: Gemini 3 Pro</span>
        <span className="flex items-center gap-1"><Palette className="w-3 h-3" /> Image: Gemini 2.5 Flash Image</span>
      </div>
    </div>
  );
};

export default PromptInput;
import { BrainCircuit } from 'lucide-react';

import React, { useState, useCallback } from 'react';
import JSZip from 'jszip';
import { DESIGN_ASSET_CONFIG, PRODUCT_MOCKUP_CONFIGS, INITIAL_IMAGES } from './constants';
import { GeneratedImage, GenerationStatus, DesignStrategy } from './types';
import { generateMockupImage, generateDesignStrategy } from './services/geminiService';
import Header from './components/Header';
import PromptInput from './components/PromptInput';
import ImageCard from './components/ImageCard';
import { CheckCircle2, RefreshCw, Download, Loader2, BrainCircuit } from 'lucide-react';

const App: React.FC = () => {
  const [images, setImages] = useState<GeneratedImage[]>(INITIAL_IMAGES);
  const [currentSlogan, setCurrentSlogan] = useState<string>('');
  const [currentNiche, setCurrentNiche] = useState<string>('');
  const [currentAudience, setCurrentAudience] = useState<string>('');
  const [designStrategy, setDesignStrategy] = useState<DesignStrategy | null>(null);
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);
  const [isZipping, setIsZipping] = useState(false);

  const handleGenerateDesign = async (
    slogan: string, 
    niche: string, 
    styleContext: string, 
    audience: string, 
    colorContext: string
  ) => {
    setCurrentSlogan(slogan);
    setCurrentNiche(niche);
    setCurrentAudience(audience);
    setStatus(GenerationStatus.ANALYZING);

    setImages(INITIAL_IMAGES.map(img => ({ ...img, loading: img.configId === DESIGN_ASSET_CONFIG.id, error: null, imageUrl: null })));

    try {
      const strategy = await generateDesignStrategy(slogan, niche, styleContext, audience, colorContext);
      setDesignStrategy(strategy);

      setStatus(GenerationStatus.GENERATING_ASSET);
      const base64Url = await generateMockupImage(DESIGN_ASSET_CONFIG.template(slogan, strategy));

      setImages(prev => prev.map(img => 
        img.configId === DESIGN_ASSET_CONFIG.id 
          ? { ...img, loading: false, imageUrl: base64Url }
          : img
      ));
      setStatus(GenerationStatus.REVIEW_ASSET);
    } catch (error) {
      setImages(prev => prev.map(img => 
        img.configId === DESIGN_ASSET_CONFIG.id 
          ? { ...img, loading: false, error: 'Failed to generate design asset.' }
          : img
      ));
      setStatus(GenerationStatus.ERROR);
    }
  };

  const handleRegenerateDesign = async () => {
    if (!currentSlogan) return;

    setStatus(GenerationStatus.GENERATING_ASSET);
    setImages(prev => prev.map(img => 
        img.configId === DESIGN_ASSET_CONFIG.id ? { ...img, loading: true, error: null } : img
    ));

    try {
        const base64Url = await generateMockupImage(DESIGN_ASSET_CONFIG.template(currentSlogan, designStrategy || undefined));

        setImages(prev => prev.map(img => 
          img.configId === DESIGN_ASSET_CONFIG.id 
            ? { ...img, loading: false, imageUrl: base64Url }
            : img
        ));
        setStatus(GenerationStatus.REVIEW_ASSET);
    } catch (error) {
        setImages(prev => prev.map(img => 
            img.configId === DESIGN_ASSET_CONFIG.id ? { ...img, loading: false, error: 'Retry failed.' } : img
        ));
        setStatus(GenerationStatus.ERROR);
    }
  };

  const handleApproveAndGenerateMockups = async () => {
    const designAsset = images.find(img => img.configId === DESIGN_ASSET_CONFIG.id);
    if (!designAsset?.imageUrl || !designStrategy) return;

    setStatus(GenerationStatus.GENERATING_MOCKUPS);

    setImages(prev => prev.map(img => 
      img.configId !== DESIGN_ASSET_CONFIG.id 
        ? { ...img, loading: true, error: null } 
        : img
    ));

    PRODUCT_MOCKUP_CONFIGS.forEach((config) => {
      generateSingleMockup(config.id, config.template(currentSlogan, designStrategy), designAsset.imageUrl!);
    });
  };

  const generateSingleMockup = async (configId: string, prompt: string, referenceImage: string) => {
    try {
      const base64Url = await generateMockupImage(prompt, referenceImage);
      setImages((prev) =>
        prev.map((img) =>
          img.configId === configId ? { ...img, loading: false, imageUrl: base64Url } : img
        )
      );
    } catch (error) {
      setImages((prev) =>
        prev.map((img) =>
          img.configId === configId ? { ...img, loading: false, error: 'Generation error.' } : img
        )
      );
    }
  };

  React.useEffect(() => {
    const isMockupsLoading = images.filter(i => i.configId !== DESIGN_ASSET_CONFIG.id).some(img => img.loading);
    if (!isMockupsLoading && status === GenerationStatus.GENERATING_MOCKUPS) {
      setStatus(GenerationStatus.COMPLETED);
    }
  }, [images, status]);

  const handleRetry = useCallback((configId: string) => {
    if (!currentSlogan) return;
    if (configId === DESIGN_ASSET_CONFIG.id) {
      handleRegenerateDesign();
      return;
    }
    const designAsset = images.find(img => img.configId === DESIGN_ASSET_CONFIG.id);
    const config = PRODUCT_MOCKUP_CONFIGS.find(c => c.id === configId);
    if (config && designAsset?.imageUrl) {
      setImages((prev) =>
        prev.map((img) => img.configId === configId ? { ...img, loading: true, error: null } : img)
      );
      generateSingleMockup(configId, config.template(currentSlogan, designStrategy || undefined), designAsset.imageUrl);
    }
  }, [currentSlogan, images, designStrategy]);

  const handleDownloadAll = async () => {
    setIsZipping(true);
    const zip = new JSZip();
    const folder = zip.folder(`pod-mockups-${Date.now()}`);
    if (folder) {
      images.forEach((img) => {
        if (img.imageUrl) {
          const data = img.imageUrl.split(',')[1];
          const cleanTitle = img.title.replace(/[^\w\s]/gi, '').replace(/\s+/g, '_');
          folder.file(`${cleanTitle}.png`, data, { base64: true });
        }
      });
      try {
        const content = await zip.generateAsync({ type: 'blob' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(content);
        link.download = `mockups-${currentSlogan.slice(0, 15)}.zip`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
      } catch (err) {
        console.error("Zipping failed", err);
      }
    }
    setIsZipping(false);
  };

  const getStatusText = () => {
    if (status === GenerationStatus.ANALYZING) return "AI Strategist is thinking...";
    if (status === GenerationStatus.GENERATING_ASSET) return "Drafting Design Asset...";
    return "Processing...";
  }

  return (
    <div className="min-h-screen pb-20 bg-slate-900">
      <Header />

      <div className={status === GenerationStatus.REVIEW_ASSET || status === GenerationStatus.GENERATING_MOCKUPS ? 'pointer-events-none opacity-40 filter blur-sm transition-all duration-500' : 'transition-all duration-500'}>
         <PromptInput 
          onGenerate={handleGenerateDesign} 
          isGenerating={status === GenerationStatus.ANALYZING || status === GenerationStatus.GENERATING_ASSET}
          statusText={getStatusText()}
        />
      </div>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-12">
        {(status === GenerationStatus.REVIEW_ASSET || status === GenerationStatus.GENERATING_ASSET || status === GenerationStatus.ANALYZING) && (
           <div className="flex flex-col items-center animate-in fade-in slide-in-from-bottom-8 duration-700">
             <div className="w-full max-w-lg mb-8">
               <div className="flex items-center justify-between mb-4 px-2">
                 <h2 className="text-2xl font-bold text-white">
                   {status === GenerationStatus.ANALYZING ? 'Crafting Strategy...' : 'Step 1: Design Review'}
                 </h2>
                 <span className="text-xs bg-indigo-500/20 text-indigo-400 px-3 py-1 rounded-full border border-indigo-500/30 uppercase tracking-widest font-bold">Vector Draft</span>
               </div>

               {designStrategy && status === GenerationStatus.REVIEW_ASSET && (
                 <div className="mb-6 p-5 bg-slate-800 rounded-xl border border-slate-700 shadow-2xl">
                   <div className="flex items-center gap-3 mb-4 text-indigo-400 font-bold uppercase text-xs tracking-widest border-b border-slate-700 pb-3">
                     <BrainCircuit className="w-4 h-4" />
                     Market Insight
                   </div>
                   <div className="grid grid-cols-2 gap-4 text-sm">
                      <div>
                        <p className="text-slate-500 text-[10px] uppercase font-bold mb-1">Target Niche</p>
                        <p className="text-white font-medium capitalize">{currentNiche}</p>
                      </div>
                      <div>
                        <p className="text-slate-500 text-[10px] uppercase font-bold mb-1">Audience</p>
                        <p className="text-white font-medium capitalize">{currentAudience || 'General'}</p>
                      </div>
                      <div className="col-span-2">
                        <p className="text-slate-500 text-[10px] uppercase font-bold mb-1">Art Direction</p>
                        <p className="text-slate-300 text-xs leading-relaxed">{designStrategy.designStyle.typography} — {designStrategy.designStyle.artStyle}</p>
                      </div>
                   </div>
                 </div>
               )}

               {images.filter(i => i.configId === DESIGN_ASSET_CONFIG.id).map(image => (
                 <ImageCard key={image.id} image={image} onRetry={handleRetry} />
               ))}
             </div>

             {status === GenerationStatus.REVIEW_ASSET && (
               <div className="flex flex-col sm:flex-row gap-4 mb-20">
                 <button 
                    onClick={handleRegenerateDesign}
                    className="flex items-center justify-center gap-2 px-8 py-4 bg-slate-800 hover:bg-slate-700 text-white font-bold rounded-xl transition-all border border-slate-700"
                 >
                   <RefreshCw className="w-5 h-5" />
                   Tweak Design
                 </button>
                 <button 
                    onClick={handleApproveAndGenerateMockups}
                    className="flex items-center justify-center gap-2 px-10 py-4 bg-green-600 hover:bg-green-500 text-white font-bold rounded-xl transition-all shadow-xl shadow-green-600/20"
                 >
                   <CheckCircle2 className="w-5 h-5" />
                   Looks Good, Mock It Up!
                 </button>
               </div>
             )}
           </div>
        )}

        {(status === GenerationStatus.GENERATING_MOCKUPS || status === GenerationStatus.COMPLETED) && (
          <div className="animate-in fade-in duration-1000">
             <div className="flex flex-col md:flex-row justify-between items-end mb-8 gap-4 border-b border-slate-800 pb-6">
                <div>
                   <h2 className="text-3xl font-extrabold text-white">Market-Ready Mockups</h2>
                   <p className="text-slate-400 mt-1">High-quality lifestyle visuals optimized for e-commerce.</p>
                </div>
                {status === GenerationStatus.COMPLETED && (
                  <button 
                    onClick={handleDownloadAll}
                    disabled={isZipping}
                    className="flex items-center gap-2 px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all shadow-xl shadow-indigo-600/30 disabled:opacity-50"
                  >
                    {isZipping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                    Download All Assets
                  </button>
                )}
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {images.map((image) => (
                  <ImageCard 
                    key={image.id} 
                    image={image} 
                    onRetry={handleRetry} 
                  />
                ))}
             </div>

             {status === GenerationStatus.COMPLETED && (
                <div className="mt-16 text-center">
                    <button 
                       onClick={() => {
                         setStatus(GenerationStatus.IDLE);
                         setImages(INITIAL_IMAGES);
                         setCurrentSlogan('');
                         setDesignStrategy(null);
                       }}
                       className="px-8 py-3 rounded-full border border-slate-700 text-slate-400 hover:text-white hover:border-slate-500 transition-all text-sm font-semibold"
                    >
                      Create Another Collection
                    </button>
                </div>
             )}
          </div>
        )}
      </main>
    </div>
  );
};

