import React, { useState, useEffect } from 'react';
import { Wand2, Loader2, Sparkles, PenTool, Paintbrush, Users, Palette, BrainCircuit, Film, RefreshCw } from 'lucide-react';
import { NICHES, DESIGN_STYLES, COLOR_PALETTES } from '../constants';
import { GenerationStatus } from '../types';

interface PromptInputProps {
  onGenerate: (slogan: string, niche: string, styleContext: string, audience: string, colorContext: string, nicheId: string, styleId: string, colorId: string) => void;
  isGenerating: boolean;
  status: GenerationStatus;
  statusText?: string;
  initialSlogan?: string;
  initialNicheId?: string;
  initialAudience?: string;
  initialStyleId?: string;
  initialColorId?: string;
}

const PromptInput: React.FC<PromptInputProps> = ({ 
  onGenerate, 
  isGenerating, 
  status,
  statusText,
  initialSlogan = '',
  initialNicheId = NICHES[0].id,
  initialAudience = '',
  initialStyleId = DESIGN_STYLES[0].id,
  initialColorId = COLOR_PALETTES[0].id
}) => {
  const [slogan, setSlogan] = useState(initialSlogan);
  const [selectedNicheId, setSelectedNicheId] = useState(initialNicheId);
  const [customNiche, setCustomNiche] = useState('');
  const [selectedStyleId, setSelectedStyleId] = useState(initialStyleId);
  const [selectedColorId, setSelectedColorId] = useState(initialColorId);
  const [audience, setAudience] = useState(initialAudience);

  useEffect(() => {
    setSlogan(initialSlogan);
    setSelectedNicheId(initialNicheId);
    setAudience(initialAudience);
    setSelectedStyleId(initialStyleId);
    setSelectedColorId(initialColorId);
  }, [initialSlogan, initialNicheId, initialAudience, initialStyleId, initialColorId]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let finalNiche = '';
    if (selectedNicheId === 'custom') {
        finalNiche = customNiche.trim();
    } else {
        const nicheObj = NICHES.find(n => n.id === selectedNicheId);
        finalNiche = nicheObj ? nicheObj.label : selectedNicheId;
    }

    const styleObj = DESIGN_STYLES.find(s => s.id === selectedStyleId) || DESIGN_STYLES[0];
    const colorObj = COLOR_PALETTES.find(c => c.id === selectedColorId) || COLOR_PALETTES[0];

    if (slogan.trim() && finalNiche) {
      onGenerate(slogan, finalNiche, styleObj.context, audience, colorObj.context, selectedNicheId, selectedStyleId, selectedColorId);
    }
  };

  const isCustomNiche = selectedNicheId === 'custom';
  const isReviewing = status === GenerationStatus.REVIEW_ASSET;

  return (
    <div className="w-full max-w-5xl mx-auto -mt-6 relative z-10 px-4">
      <form onSubmit={handleSubmit} className="bg-slate-800 p-6 rounded-2xl shadow-2xl border border-slate-700 flex flex-col gap-5">

        {/* Row 1: Primary Selectors */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {/* Niche & Custom */}
            <div className="flex flex-col gap-3">
                <div className="relative">
                  <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Target Niche</label>
                  <select
                    value={selectedNicheId}
                    onChange={(e) => setSelectedNicheId(e.target.value)}
                    className="w-full appearance-none bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm pr-10"
                    disabled={isGenerating}
                  >
                    {NICHES.map((n) => (
                        <option key={n.id} value={n.id}>{n.label}</option>
                    ))}
                  </select>
                  <Sparkles className="absolute right-3 top-[34px] w-4 h-4 text-slate-500 pointer-events-none" />
                </div>
                {isCustomNiche && (
                    <input
                        type="text"
                        value={customNiche}
                        onChange={(e) => setCustomNiche(e.target.value)}
                        placeholder="Type niche..."
                        className="w-full bg-slate-900 text-white px-4 py-3 rounded-xl border border-indigo-500/50 focus:outline-none focus:ring-2 focus:ring-indigo-500 text-sm"
                        disabled={isGenerating}
                    />
                )}
            </div>

            {/* Style Selector */}
            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Visual Trend</label>
                <select
                    value={selectedStyleId}
                    onChange={(e) => setSelectedStyleId(e.target.value)}
                    className="w-full appearance-none bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm pr-10"
                    disabled={isGenerating}
                >
                    {DESIGN_STYLES.map((s) => (
                        <option key={s.id} value={s.id}>{s.label}</option>
                    ))}
                </select>
                <Paintbrush className="absolute right-3 top-10 w-4 h-4 text-slate-500 pointer-events-none" />
            </div>

            {/* Color Palette Selector */}
            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Color Palette</label>
                <div className="grid grid-cols-3 gap-2">
                    {COLOR_PALETTES.map((cp) => (
                        <button
                            key={cp.id}
                            type="button"
                            onClick={() => setSelectedColorId(cp.id)}
                            className={`p-1 rounded-lg border transition-all ${selectedColorId === cp.id ? 'border-indigo-500 bg-indigo-500/10' : 'border-slate-700 bg-slate-900 hover:border-slate-500'}`}
                            title={cp.label}
                            disabled={isGenerating}
                        >
                            <div className="flex gap-0.5 mb-1 justify-center">
                                {cp.colors.map((c, i) => (
                                    <div key={i} className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: c }} />
                                ))}
                            </div>
                            <span className="text-[10px] text-slate-400 block truncate">{cp.label}</span>
                        </button>
                    ))}
                </div>
            </div>
        </div>

        {/* Row 2: Audience & Slogan */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Who is this for? (Audience)</label>
                <div className="relative">
                    <input
                        type="text"
                        value={audience}
                        onChange={(e) => setAudience(e.target.value)}
                        placeholder="e.g., Cat Lovers, Proud Teachers, Gen Z..."
                        className="w-full bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm pl-10"
                        disabled={isGenerating}
                    />
                    <Users className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                </div>
            </div>

            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Slogan / Text on Shirt</label>
                <input
                    type="text"
                    value={slogan}
                    onChange={(e) => setSlogan(e.target.value)}
                    placeholder="e.g., 'Not all who wander are lost'"
                    className="w-full bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-medium"
                    disabled={isGenerating}
                />
            </div>
        </div>

        {/* Submit Button */}
        <button
          type="submit"
          disabled={isGenerating || !slogan.trim()}
          className={`w-full font-bold px-8 py-4 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2
            ${isReviewing 
              ? 'bg-slate-700 hover:bg-slate-600 text-white shadow-slate-700/30'
              : 'bg-gradient-to-r from-indigo-600 to-indigo-500 hover:from-indigo-500 hover:to-indigo-400 text-white shadow-indigo-500/30'
            }
            disabled:opacity-50 disabled:cursor-not-allowed`}
        >
          {isGenerating ? (
            <>
              <Loader2 className="w-5 h-5 animate-spin" />
              <span>{statusText || 'Brainstorming Market Strategy...'}</span>
            </>
          ) : isReviewing ? (
            <>
              <RefreshCw className="w-5 h-5" />
              <span>Tweak & Regenerate Design</span>
            </>
          ) : (
            <>
              <Wand2 className="w-5 h-5" />
              <span>Generate Viral Design & Mockups</span>
            </>
          )}
        </button>
      </form>
      <div className="text-center mt-4 text-slate-500 text-xs flex items-center justify-center gap-3">
        <span className="flex items-center gap-1"><BrainCircuit className="w-3 h-3" /> Strategy: Gemini 3 Pro</span>
        <span className="flex items-center gap-1"><Palette className="w-3 h-3" /> Image: Gemini Flash Image</span>
        <span className="flex items-center gap-1"><Film className="w-3 h-3" /> Video: Veo</span>
      </div>
    </div>
  );
};

export default PromptInput;

import React, { useState, useCallback, useEffect } from 'react';
import JSZip from 'jszip';
import { DESIGN_ASSET_CONFIG, PRODUCT_MOCKUP_CONFIGS, INITIAL_IMAGES, ALL_CONFIGS } from './constants';
import { GeneratedImage, GenerationStatus, DesignStrategy } from './types';
import { generateMockupImage, generateDesignStrategy, generatePromoVideo, generateVideoPrompt } from './services/geminiService';
import Header from './components/Header';
import PromptInput from './components/PromptInput';
import ImageCard from './components/ImageCard';
import { CheckCircle2, RefreshCw, Download, Loader2, BrainCircuit, Key, AlertCircle, Film, ExternalLink, FileText, Clipboard, X } from 'lucide-react';

const App: React.FC = () => {
  const [images, setImages] = useState<GeneratedImage[]>(INITIAL_IMAGES);
  const [designStrategy, setDesignStrategy] = useState<DesignStrategy | null>(null);
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);

  // State to hold current prompt inputs
  const [currentSlogan, setCurrentSlogan] = useState<string>('');
  const [currentNiche, setCurrentNiche] = useState<string>('');
  const [currentNicheId, setCurrentNicheId] = useState<string>('');
  const [currentAudience, setCurrentAudience] = useState<string>('');
  const [currentStyleId, setCurrentStyleId] = useState<string>('');
  const [currentStyleContext, setCurrentStyleContext] = useState<string>('');
  const [currentColorId, setCurrentColorId] = useState<string>('');
  const [currentColorContext, setCurrentColorContext] = useState<string>('');

  const [isZipping, setIsZipping] = useState(false);
  const [hasApiKey, setHasApiKey] = useState(false);

  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [isVideoGenerating, setIsVideoGenerating] = useState(false);
  const [videoError, setVideoError] = useState<string | null>(null);

  const [videoPrompt, setVideoPrompt] = useState<string | null>(null);
  const [isVideoPromptGenerating, setIsVideoPromptGenerating] = useState(false);
  const [isVideoPromptModalOpen, setIsVideoPromptModalOpen] = useState(false);
  const [hasCopied, setHasCopied] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      setHasApiKey(hasKey);
    };
    checkKey();
  }, []);

  const resetAppState = () => {
    setStatus(GenerationStatus.IDLE);
    setImages(INITIAL_IMAGES);
    setCurrentSlogan('');
    setCurrentNiche('');
    setCurrentNicheId('');
    setCurrentAudience('');
    setCurrentStyleId('');
    setCurrentStyleContext('');
    setCurrentColorId('');
    setCurrentColorContext('');
    setDesignStrategy(null);
    setVideoUrl(null);
    setIsVideoGenerating(false);
    setVideoError(null);
    setVideoPrompt(null);
    setIsVideoPromptGenerating(false);
    setIsVideoPromptModalOpen(false);
  };

  const handleOpenKeySelector = async () => {
    // @ts-ignore
    await window.aistudio.openSelectKey();
    setHasApiKey(true); 
  };

  const handleError = (error: any, configId?: string) => {
    const isPermissionError = error?.message?.includes('403') || error?.message?.includes('PERMISSION_DENIED');
    const isQuotaError = !isPermissionError && (error?.message?.includes('429') || error?.message?.includes('RESOURCE_EXHAUSTED') || error?.message?.includes('API key not valid'));

    let errorMessage = error.message || 'An unknown error occurred.';
    if (isPermissionError) {
        errorMessage = "Permission Denied: Please enable the 'Vertex AI API' in your Google Cloud project.";
    } else if (isQuotaError) {
        errorMessage = 'API Quota/Key Error: Please connect a valid, paid API key.';
    }

    if (configId) {
      setImages(prev => prev.map(img => 
        img.configId === configId ? { ...img, loading: false, error: errorMessage } : img
      ));
    }

    // Set global error status if it's a key-related issue
    if (isQuotaError || isPermissionError) {
      setStatus(GenerationStatus.ERROR);
    }
  };

  const startDesignGeneration = async (slogan: string, niche: string, styleContext: string, audience: string, colorContext: string) => {
    setStatus(GenerationStatus.ANALYZING);
    // Set loading state only for the main design asset
    setImages(prev => prev.map(img => ({ 
      ...img, 
      loading: img.configId === DESIGN_ASSET_CONFIG.id,
      // Clear old mockups if this is a regeneration
      imageUrl: img.configId !== DESIGN_ASSET_CONFIG.id ? null : img.imageUrl,
      error: null
    })));

    try {
      const strategy = await generateDesignStrategy(slogan, niche, styleContext, audience, colorContext);
      setDesignStrategy(strategy);
      setStatus(GenerationStatus.GENERATING_ASSET);
      const base64Url = await generateMockupImage(DESIGN_ASSET_CONFIG.template(slogan, strategy));
      setImages(prev => prev.map(img => 
        img.configId === DESIGN_ASSET_CONFIG.id ? { ...img, loading: false, imageUrl: base64Url } : img
      ));
      setStatus(GenerationStatus.REVIEW_ASSET);
    } catch (error) {
      handleError(error, DESIGN_ASSET_CONFIG.id);
      setStatus(GenerationStatus.REVIEW_ASSET); // Go to review state even on error to allow tweaking
    }
  };

  const handleGenerateDesign = async (slogan: string, niche: string, styleContext: string, audience: string, colorContext: string, nicheId: string, styleId: string, colorId: string) => {
    resetAppState();
    setCurrentSlogan(slogan);
    setCurrentNiche(niche);
    setCurrentNicheId(nicheId);
    setCurrentAudience(audience);
    setCurrentStyleId(styleId);
    setCurrentStyleContext(styleContext);
    setCurrentColorId(colorId);
    setCurrentColorContext(colorContext);
    startDesignGeneration(slogan, niche, styleContext, audience, colorContext);
  };

  const handleRegenerateDesign = async (slogan: string, niche: string, styleContext: string, audience: string, colorContext: string, nicheId: string, styleId: string, colorId: string) => {
    // Update state with new values from PromptInput
    setCurrentSlogan(slogan);
    setCurrentNiche(niche);
    setCurrentNicheId(nicheId);
    setCurrentAudience(audience);
    setCurrentStyleId(styleId);
    setCurrentStyleContext(styleContext);
    setCurrentColorId(colorId);
    setCurrentColorContext(colorContext);

    // Clear previous design asset and all mockups before regenerating
    setImages(INITIAL_IMAGES);

    startDesignGeneration(slogan, niche, styleContext, audience, colorContext);
  };


  const handleApproveAndGenerateMockups = async () => {
    const designAsset = images.find(img => img.configId === DESIGN_ASSET_CONFIG.id);
    if (!designAsset?.imageUrl || !designStrategy) return;
    setStatus(GenerationStatus.GENERATING_MOCKUPS);
    setImages(prev => prev.map(img => img.configId !== DESIGN_ASSET_CONFIG.id ? { ...img, loading: true, error: null } : img));
    PRODUCT_MOCKUP_CONFIGS.forEach((config) => {
      generateSingleMockup(config.id, config.template(currentSlogan, designStrategy), designAsset.imageUrl!);
    });
  };

  const generateSingleMockup = async (configId: string, prompt: string, referenceImage: string) => {
    try {
      const base64Url = await generateMockupImage(prompt, referenceImage);
      setImages(prev => prev.map(img => img.configId === configId ? { ...img, loading: false, imageUrl: base64Url } : img));
    } catch (error) {
      handleError(error, configId);
    }
  };

  const handleGenerateVideo = async () => {
    if (!designStrategy || !currentSlogan) return;

    setIsVideoGenerating(true);
    setVideoUrl(null);
    setVideoError(null);

    try {
      const referenceImageIds = ['tshirt-mockup', 'hoodie-mockup', 'phonecase-mockup'];
      const referenceImages = images
        .filter(img => referenceImageIds.includes(img.configId) && img.imageUrl)
        .map(img => img.imageUrl!);

      if (referenceImages.length < 1) {
        throw new Error("Not enough successful mockups to generate a video.");
      }

      const url = await generatePromoVideo(currentSlogan, designStrategy, referenceImages);
      setVideoUrl(url);

    } catch (error: any) {
      const isPermissionError = error?.message?.includes('403') || error?.message?.includes('PERMISSION_DENIED');
      const isQuotaError = !isPermissionError && (error?.message?.includes('429') || error?.message?.includes('RESOURCE_EXHAUSTED') || error?.message?.includes('not found'));

      let videoErrorMessage = 'Video generation failed. Please try again.';
      if (isPermissionError) {
        videoErrorMessage = 'Permission Denied. Please ensure the "Vertex AI API" is enabled in your Google Cloud project to generate videos.';
      } else if (isQuotaError) {
        videoErrorMessage = 'Video generation requires a valid paid API Key with sufficient quota. Please check your key and billing status.';
      } else if (error.message) {
        videoErrorMessage = error.message;
      }
      setVideoError(videoErrorMessage);
    } finally {
      setIsVideoGenerating(false);
    }
  };

  const handleGenerateVideoPrompt = async () => {
    if (!designStrategy || !currentSlogan || !currentNiche) return;

    const successfulMockups = images
      .filter(img => img.imageUrl && img.configId !== DESIGN_ASSET_CONFIG.id)
      .map(img => img.imageUrl!);

    if (successfulMockups.length === 0) {
      alert("Please generate some mockups before creating a video script.");
      return;
    }

    setIsVideoPromptGenerating(true);
    setVideoPrompt(null);
    try {
      const prompt = await generateVideoPrompt(currentSlogan, currentNiche, currentAudience, designStrategy, successfulMockups);
      setVideoPrompt(prompt);
      setIsVideoPromptModalOpen(true);
    } catch(e) {
      // Simple error handling for prompt generation
      alert("Sorry, the AI Director is busy. Please try again in a moment.");
    } finally {
      setIsVideoPromptGenerating(false);
    }
  };

  const handleCopyPrompt = () => {
    if (videoPrompt) {
      navigator.clipboard.writeText(videoPrompt);
      setHasCopied(true);
      setTimeout(() => setHasCopied(false), 2000);
    }
  };

  useEffect(() => {
    const isMockupsLoading = images.filter(i => i.configId !== DESIGN_ASSET_CONFIG.id).some(img => img.loading);
    if (!isMockupsLoading && status === GenerationStatus.GENERATING_MOCKUPS) {
      setStatus(GenerationStatus.COMPLETED);
    }
  }, [images, status]);

  const handleRetry = useCallback((configId: string) => {
    if (!currentSlogan) return;
    if (configId === DESIGN_ASSET_CONFIG.id) {
       // Re-trigger regeneration using the existing parameters from state
       startDesignGeneration(currentSlogan, currentNiche, currentStyleContext, currentAudience, currentColorContext);
       return;
    }
    const designAsset = images.find(img => img.configId === DESIGN_ASSET_CONFIG.id);
    const config = PRODUCT_MOCKUP_CONFIGS.find(c => c.id === configId);
    if (config && designAsset?.imageUrl) {
      setImages(prev => prev.map(img => img.configId === configId ? { ...img, loading: true, error: null } : img));
      generateSingleMockup(configId, config.template(currentSlogan, designStrategy || undefined), designAsset.imageUrl);
    }
  }, [currentSlogan, currentNiche, currentStyleContext, currentAudience, currentColorContext, images, designStrategy]);


  const handleDownloadAll = async () => {
    setIsZipping(true);
    const zip = new JSZip();
    const folder = zip.folder(`pod-assets-${Date.now()}`);
    if (folder) {
      const sortedImages = [...images].sort((a, b) => {
        const indexA = ALL_CONFIGS.findIndex(c => c.id === a.configId);
        const indexB = ALL_CONFIGS.findIndex(c => c.id === b.configId);
        return indexA - indexB;
      });

      sortedImages.forEach(img => {
        if (img.imageUrl) {
          const sanitizedTitle = img.title
            .replace(/\s/g, '_')
            .replace(/[&/]/g, '-')
            .replace(/[()]/g, '');
          folder.file(`${sanitizedTitle}.png`, img.imageUrl.split(',')[1], { base64: true });
        }
      });
      if (videoUrl) {
        try {
          const response = await fetch(videoUrl);
          const blob = await response.blob();
          folder.file('promo_video.mp4', blob);
        } catch (e) {
          console.error("Could not add video to zip", e);
        }
      }
      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `pod_assets_${currentSlogan.replace(/\s/g, '_').slice(0, 15)}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
    setIsZipping(false);
  };

  const getStatusText = () => {
    if (status === GenerationStatus.ANALYZING) return "AI Strategist is thinking...";
    if (status === GenerationStatus.GENERATING_ASSET) return "Drafting Design Asset...";
    return "Processing...";
  }

  const firstError = images.find(img => img.error)?.error;
  const isPermissionError = firstError?.includes('Permission Denied');

  return (
    <div className="min-h-screen pb-20 bg-slate-900">
      <Header />

      {!hasApiKey && (
        <div className="max-w-5xl mx-auto px-4 mt-6">
          <div className="bg-amber-500/10 border border-amber-500/30 rounded-xl p-4 flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <AlertCircle className="w-5 h-5 text-amber-500" />
              <div>
                <p className="text-amber-200 text-sm font-semibold">High Quality & No Quota Limits</p>
                <p className="text-amber-200/60 text-xs">Connect your own paid API key to unlock high-quality models.</p>
              </div>
            </div>
            <button 
              onClick={handleOpenKeySelector}
              className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-400 text-slate-900 font-bold rounded-lg transition-all text-sm whitespace-nowrap"
            >
              <Key className="w-4 h-4" />
              Connect Paid Key
            </button>
          </div>
          <p className="text-slate-500 text-[10px] mt-2 px-2">
            Requires a paid GCP project key. Learn more at <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener noreferrer" className="underline">ai.google.dev/gemini-api/docs/billing</a>
          </p>
        </div>
      )}

      <div className="transition-all duration-500">
         <PromptInput 
            onGenerate={status === GenerationStatus.REVIEW_ASSET ? handleRegenerateDesign : handleGenerateDesign} 
            isGenerating={status === GenerationStatus.ANALYZING || status === GenerationStatus.GENERATING_ASSET} 
            status={status}
            statusText={getStatusText()}
            initialSlogan={currentSlogan}
            initialNicheId={currentNicheId}
            initialAudience={currentAudience}
            initialStyleId={currentStyleId}
            initialColorId={currentColorId}
         />
      </div>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-12">
        {status === GenerationStatus.ERROR && (
          <div className="flex flex-col items-center justify-center p-12 bg-slate-800 rounded-3xl border border-rose-500/30 mb-8">
            <AlertCircle className="w-16 h-16 text-rose-500 mb-4" />
            <h3 className="text-xl font-bold text-white mb-2">{isPermissionError ? 'Permission Denied' : 'Generation Failed'}</h3>

            {isPermissionError ? (
              <>
                <p className="text-slate-400 text-center max-w-md mb-6">
                  Your API key is valid, but lacks permissions. Please enable the <strong>Vertex AI API</strong> in your Google Cloud project to proceed.
                </p>
                <div className="flex flex-col sm:flex-row gap-4">
                    <a 
                      href="https://console.cloud.google.com/apis/library/aiplatform.googleapis.com"
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex items-center justify-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all shadow-xl shadow-indigo-600/30"
                    >
                      <ExternalLink className="w-5 h-5" />
                      Enable Vertex AI API
                    </a>
                    <button 
                      onClick={handleOpenKeySelector}
                      className="flex items-center justify-center gap-2 px-6 py-3 bg-slate-700 hover:bg-slate-600 text-white font-bold rounded-xl transition-all"
                    >
                      <Key className="w-5 h-5" />
                      Use Different Key
                    </button>
                </div>
              </>
            ) : (
              <>
                <p className="text-slate-400 text-center max-w-md mb-6">
                  You may have hit API quota limits or the key is invalid. To continue generating, please connect your personal paid API key.
                </p>
                <button 
                  onClick={handleOpenKeySelector}
                  className="flex items-center gap-2 px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all shadow-xl shadow-indigo-600/30"
                >
                  <Key className="w-5 h-5" />
                  Connect Personal Key & Retry
                </button>
              </>
            )}
          </div>
        )}

        {(status !== GenerationStatus.IDLE && status !== GenerationStatus.ERROR) && (
           <div className="flex flex-col items-center animate-in fade-in slide-in-from-bottom-8 duration-700">
             <div className="w-full max-w-lg mb-8">
               <div className="flex items-center justify-between mb-4 px-2">
                 <h2 className="text-2xl font-bold text-white">
                   {status === GenerationStatus.ANALYZING ? 'Crafting Strategy...' : 'Step 1: Design Review'}
                 </h2>
                 <span className="text-xs bg-indigo-500/20 text-indigo-400 px-3 py-1 rounded-full border border-indigo-500/30 uppercase tracking-widest font-bold">Vector Draft</span>
               </div>

               {designStrategy && (status === GenerationStatus.REVIEW_ASSET || status === GenerationStatus.GENERATING_MOCKUPS || status === GenerationStatus.COMPLETED) && (
                 <div className="mb-6 p-5 bg-slate-800 rounded-xl border border-slate-700 shadow-2xl">
                   <div className="flex items-center gap-3 mb-4 text-indigo-400 font-bold uppercase text-xs tracking-widest border-b border-slate-700 pb-3">
                     <BrainCircuit className="w-4 h-4" />
                     Market Insight
                   </div>
