export const suggestStrategyPresets = async (slogan: string, audience: string): Promise<StrategySuggestion> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    // Pass the available options to the AI so it can return valid IDs
    const nicheOptions = NICHES.map(n => `ID: "${n.id}", Label: "${n.label}"`).join('\n');
    const styleOptions = DESIGN_STYLES.map(s => `ID: "${s.id}", Label: "${s.label}", Context: "${s.context}"`).join('\n');
    const colorOptions = COLOR_PALETTES.map(c => `ID: "${c.id}", Label: "${c.label}", Context: "${c.context}"`).join('\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `You are an expert Print-on-Demand (POD) market trend analyst with deep knowledge of best-selling designs on Etsy, Redbubble, and Amazon Merch.
      Your task is to analyze the provided slogan and target audience, then suggest the optimal 'Target Niche', 'Visual Trend', and 'Color Palette' for maximum commercial success.
      Base your suggestions on current market trends and data from best-sellers.

      **Slogan:** "${slogan}"
      **Target Audience:** "${audience || 'General public'}"

      **Available Options (You MUST return one ID from each category):**

      **Target Niches:**
      ${nicheOptions}

      **Visual Trends:**
      ${styleOptions}

      **Color Palettes:**
      ${colorOptions}

      **Instructions:**
      1.  Analyze the slogan's content, tone, and potential appeal.
      2.  Consider the target audience's likely preferences.
      3.  Cross-reference this with your knowledge of what is currently popular and selling well in the POD market.
      4.  Select the single best ID from each of the three categories provided.
      5.  Provide a brief, insightful 'rationale' explaining why this combination is a strong commercial strategy.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nicheId: { type: Type.STRING },
            styleId: { type: Type.STRING },
            colorId: { type: Type.STRING },
            rationale: { type: Type.STRING, description: "Your reasoning for choosing this strategy, citing market trends." },
          },
          required: ["nicheId", "styleId", "colorId", "rationale"]
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as StrategySuggestion;
    }
    throw new Error("No strategy suggestion generated");
  } catch (error) {
    console.error("Error suggesting strategy:", error);
    throw error;
  }
};

