  const [isZipping, setIsZipping] = useState(false);
  const [hasApiKey, setHasApiKey] = useState(false);

  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [isVideoGenerating, setIsVideoGenerating] = useState(false);
  const [videoError, setVideoError] = useState<string | null>(null);

  const [videoPrompt, setVideoPrompt] = useState<string | null>(null);
  const [isVideoPromptGenerating, setIsVideoPromptGenerating] = useState(false);
  const [isVideoPromptModalOpen, setIsVideoPromptModalOpen] = useState(false);
  const [hasCopied, setHasCopied] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      setHasApiKey(hasKey);
    };
    checkKey();
  }, []);

  const resetAppState = () => {
    setStatus(GenerationStatus.IDLE);
    setImages(INITIAL_IMAGES);
    setCurrentSlogan('');
    setCurrentAudience('');
    setDesignStrategy(null);
    setDesignAssets([]);
    setSelectedDesignAssetId(null);
    setVideoUrl(null);
    setIsVideoGenerating(false);
    setVideoError(null);
    setVideoPrompt(null);
    setIsVideoPromptGenerating(false);
    setIsVideoPromptModalOpen(false);
  };

  const handleOpenKeySelector = async () => {
    // @ts-ignore
    await window.aistudio.openSelectKey();
    setHasApiKey(true); 
  };

  const handleError = (error: any, assetId?: string) => {
    const isPermissionError = error?.message?.includes('403') || error?.message?.includes('PERMISSION_DENIED');
    const isQuotaError = !isPermissionError && (error?.message?.includes('429') || error?.message?.includes('RESOURCE_EXHAUSTED') || error?.message?.includes('API key not valid'));

    let errorMessage = error.message || 'An unknown error occurred.';
    if (isPermissionError) {
        errorMessage = "Permission Denied: Please enable the 'Vertex AI API' in your Google Cloud project.";
    } else if (isQuotaError) {
        errorMessage = 'API Quota/Key Error: Please connect a valid, paid API key.';
    }

    if (assetId) {
      setDesignAssets(prev => prev.map(asset => 
        asset.id === assetId ? { ...asset, loading: false, error: errorMessage } : asset
      ));
    }

    if (isQuotaError || isPermissionError) {
      setStatus(GenerationStatus.ERROR);
    }
  };

  const handleStartGenerationProcess = async (slogan: string, audience: string) => {
    resetAppState();
    setCurrentSlogan(slogan);
    setCurrentAudience(audience);
    setStatus(GenerationStatus.GENERATING_5_ASSETS);

    try {
      const top5Concepts = await generateFiveDesignConcepts(slogan, audience);

      const initialAssets: DesignAsset[] = top5Concepts.map((concept, index) => ({
        id: `design-${index}`,
        imageUrl: null,
        loading: true,
        error: null,
        strategy: concept
      }));
      setDesignAssets(initialAssets);

      // Generate concepts sequentially to avoid rate limiting
      for (const asset of initialAssets) {
        try {
            // The detailed strategy is now fetched in the initial call, so we pass it directly.
            const imageUrl = await generateMockupImage(DESIGN_ASSET_CONFIG.template(slogan, { designStyle: asset.strategy.designStyle } as DesignStrategy));

            setDesignAssets(prev => prev.map(a => 
              a.id === asset.id ? { ...a, loading: false, imageUrl: imageUrl, error: null } : a
            ));
        } catch (error: any) {
            handleError(error, asset.id);
        }
        await sleep(1500); // Add a delay to prevent rate limiting
      }

      setStatus(GenerationStatus.REVIEW_5_ASSETS);

    } catch (e: any) {
      handleError(e);
      setStatus(GenerationStatus.ERROR);
    }
  };

  const handleSelectDesign = (assetId: string) => {
    setSelectedDesignAssetId(assetId);
  };

  const generateSingleMockup = useCallback(async (configId: string, prompt: string, referenceImage: string) => {
    try {
      const base64Url = await generateMockupImage(prompt, referenceImage);
      setImages(prev => prev.map(img => img.configId === configId ? { ...img, loading: false, imageUrl: base64Url } : img));
    } catch (error: any) {
      const isPermissionError = error?.message?.includes('403') || error?.message?.includes('PERMISSION_DENIED');
      const isQuotaError = !isPermissionError && (error?.message?.includes('429') || error?.message?.includes('RESOURCE_EXHAUSTED') || error?.message?.includes('API key not valid'));

      let errorMessage = error.message || 'An unknown error occurred.';
      if (isPermissionError) {
          errorMessage = "Permission Denied: Enable Vertex AI API.";
      } else if (isQuotaError) {
          errorMessage = 'API Quota/Key Error: Check key.';
      }

      setImages(prev => prev.map(img => img.configId === configId ? { ...img, loading: false, error: errorMessage } : img));

      if (isQuotaError || isPermissionError) {
        setStatus(GenerationStatus.ERROR);
      }
    }
  }, []);

  const handleApproveAndGenerateMockups = async () => {
    const selectedAsset = designAssets.find(asset => asset.id === selectedDesignAssetId);
    if (!selectedAsset?.imageUrl) return;

    setStatus(GenerationStatus.GENERATING_MOCKUPS);

    // Set the first image (design asset) for the final grid
    const finalImages: GeneratedImage[] = ALL_CONFIGS.map(config => ({
      id: config.id,
      configId: config.id,
      title: config.title,
      imageUrl: config.id === DESIGN_ASSET_CONFIG.id ? selectedAsset.imageUrl : null,
      loading: config.id !== DESIGN_ASSET_CONFIG.id,
      error: null,
    }));
    setImages(finalImages);

    // Generate detailed strategy for the selected design to guide mockups
    try {
        const nicheObj = NICHES.find(n => n.id === selectedAsset.strategy.nicheId) || NICHES[0];
        const styleObj = DESIGN_STYLES.find(s => s.id === selectedAsset.strategy.styleId) || DESIGN_STYLES[0];
        const colorObj = COLOR_PALETTES.find(c => c.id === selectedAsset.strategy.colorId) || COLOR_PALETTES[0];

        const detailedStrategy = await generateDesignStrategy(currentSlogan, nicheObj.label, styleObj.context, currentAudience, colorObj.context);
        setDesignStrategy(detailedStrategy);

        // Generate mockups sequentially with a delay
        for (const config of PRODUCT_MOCKUP_CONFIGS) {
          await generateSingleMockup(config.id, config.template(currentSlogan, detailedStrategy), selectedAsset.imageUrl!);
          await sleep(1500);
        }
    } catch (e) {
      handleError(e);
      setStatus(GenerationStatus.ERROR);
    }
  };

  const handleGenerateVideo = async () => {
    if (!designStrategy || !currentSlogan) return;

    setIsVideoGenerating(true);
    setVideoUrl(null);
    setVideoError(null);

    try {
      const referenceImageIds = ['tshirt-mockup', 'hoodie-mockup', 'phonecase-mockup'];
      const referenceImages = images
        .filter(img => referenceImageIds.includes(img.configId) && img.imageUrl)
        .map(img => img.imageUrl!);

      if (referenceImages.length < 1) {
        throw new Error("Not enough successful mockups to generate a video.");
      }

      const url = await generatePromoVideo(currentSlogan, designStrategy, referenceImages);
      setVideoUrl(url);

    } catch (error: any) {
      const isPermissionError = error?.message?.includes('403') || error?.message?.includes('PERMISSION_DENIED');
      const isQuotaError = !isPermissionError && (error?.message?.includes('429') || error?.message?.includes('RESOURCE_EXHAUSTED') || error?.message?.includes('not found'));

      let videoErrorMessage = 'Video generation failed. Please try again.';
      if (isPermissionError) {
        videoErrorMessage = 'Permission Denied. Please ensure the "Vertex AI API" is enabled in your Google Cloud project to generate videos.';
      } else if (isQuotaError) {
        videoErrorMessage = 'Video generation requires a valid paid API Key with sufficient quota. Please check your key and billing status.';
      } else if (error.message) {
        videoErrorMessage = error.message;
      }
      setVideoError(videoErrorMessage);
    } finally {
      setIsVideoGenerating(false);
    }
  };

  const handleGenerateVideoPrompt = async () => {
    const selectedAsset = designAssets.find(asset => asset.id === selectedDesignAssetId);
    const niche = NICHES.find(n => n.id === selectedAsset?.strategy.nicheId)?.label || 'General';
    if (!designStrategy || !currentSlogan || !niche) return;

    const successfulMockups = images
      .filter(img => img.imageUrl && img.configId !== DESIGN_ASSET_CONFIG.id)
      .map(img => img.imageUrl!);

    if (successfulMockups.length === 0) {
      alert("Please generate some mockups before creating a video script.");
      return;
    }

    setIsVideoPromptGenerating(true);
    setVideoPrompt(null);
    try {
      const prompt = await generateVideoPrompt(currentSlogan, niche, currentAudience, designStrategy, successfulMockups);
      setVideoPrompt(prompt);
      setIsVideoPromptModalOpen(true);
    } catch(e) {
      // Simple error handling for prompt generation
      alert("Sorry, the AI Director is busy. Please try again in a moment.");
    } finally {
      setIsVideoPromptGenerating(false);
    }
  };

  const handleCopyPrompt = () => {
    if (videoPrompt) {
      navigator.clipboard.writeText(videoPrompt);
      setHasCopied(true);
      setTimeout(() => setHasCopied(false), 2000);
    }
  };

  useEffect(() => {
    const isMockupsLoading = images.filter(i => i.configId !== DESIGN_ASSET_CONFIG.id).some(img => img.loading);
    if (!isMockupsLoading && status === GenerationStatus.GENERATING_MOCKUPS) {
      setStatus(GenerationStatus.COMPLETED);
    }
  }, [images, status]);

  // FIX: Implement retry/regenerate functionality for individual mockups.
  const handleRetry = useCallback((configId: string) => {
    if (status === GenerationStatus.REVIEW_5_ASSETS) {
      alert("To retry a concept, please use the 'Start Over' button for a fresh set of concepts.");
      return;
    }

    if (configId === DESIGN_ASSET_CONFIG.id) return; // Cannot retry main asset here

    const selectedAsset = designAssets.find(asset => asset.id === selectedDesignAssetId);
    if (selectedAsset?.imageUrl && designStrategy && currentSlogan) {
      const config = PRODUCT_MOCKUP_CONFIGS.find(c => c.id === configId);
      if (config) {
        setImages(prev => prev.map(img => 
          img.configId === configId ? { ...img, loading: true, error: null } : img
        ));
        generateSingleMockup(config.id, config.template(currentSlogan, designStrategy), selectedAsset.imageUrl);
      }
    }
  }, [status, designAssets, selectedDesignAssetId, designStrategy, currentSlogan, generateSingleMockup]);


  const handleDownloadAll = async () => {
    setIsZipping(true);
    const zip = new JSZip();
    const folder = zip.folder(`pod-assets-${Date.now()}`);
    if (folder) {
      const sortedImages = [...images].sort((a, b) => {
        const indexA = ALL_CONFIGS.findIndex(c => c.id === a.configId);
        const indexB = ALL_CONFIGS.findIndex(c => c.id === b.configId);
        return indexA - indexB;
      });

      sortedImages.forEach(img => {
        if (img.imageUrl) {
          const sanitizedTitle = img.title
            .replace(/\s/g, '_')
            .replace(/[&/]/g, '-')
            .replace(/[()]/g, '');
          folder.file(`${sanitizedTitle}.png`, img.imageUrl.split(',')[1], { base64: true });
        }
      });
      if (videoUrl) {
        try {
          const response = await fetch(videoUrl);
          const blob = await response.blob();
          folder.file('promo_video.mp4', blob);
        } catch (e) {
          console.error("Could not add video to zip", e);
        }
      }
      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `pod_assets_${currentSlogan.replace(/\s/g, '_').slice(0, 15)}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
    setIsZipping(false);
  };

  const getStatusText = () => {
    if (status === GenerationStatus.GENERATING_5_ASSETS) return "AI is generating 5 concepts...";
    if (status === GenerationStatus.ANALYZING) return "AI Strategist is thinking...";
    return "Processing...";
  }

  const firstError = images.find(img => img.error)?.error;
  const isPermissionError = firstError?.includes('Permission Denied');
  const isGeneratingAnything = status !== GenerationStatus.IDLE && status !== GenerationStatus.COMPLETED && status !== GenerationStatus.ERROR;

  return (
    <div className="min-h-screen pb-20 bg-slate-900">
      <Header />

      {!hasApiKey && (
        <div className="max-w-5xl mx-auto px-4 mt-6">
          <div className="bg-amber-500/10 border border-amber-500/30 rounded-xl p-4 flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <AlertCircle className="w-5 h-5 text-amber-500" />
              <div>
                <p className="text-amber-200 text-sm font-semibold">High Quality & No Quota Limits</p>
                <p className="text-amber-200/60 text-xs">Connect your own paid API key to unlock high-quality models.</p>
              </div>
            </div>
            <button 
              onClick={handleOpenKeySelector}
              className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-400 text-slate-900 font-bold rounded-lg transition-all text-sm whitespace-nowrap"
            >
              <Key className="w-4 h-4" />
              Connect Paid Key
            </button>
          </div>
          <p className="text-slate-500 text-[10px] mt-2 px-2">
            Requires a paid GCP project key. Learn more at <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener noreferrer" className="underline">ai.google.dev/gemini-api/docs/billing</a>
          </p>
        </div>
      )}

      <div className="transition-all duration-500 relative">
         <PromptInput 
            onGenerate={handleStartGenerationProcess}
            isGenerating={isGeneratingAnything}
            statusText={getStatusText()}
         />
      </div>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-12">
        {status === GenerationStatus.ERROR && (
          <div className="flex flex-col items-center justify-center p-12 bg-slate-800 rounded-3xl border border-rose-500/30 mb-8">
            <AlertCircle className="w-16 h-16 text-rose-500 mb-4" />
            <h3 className="text-xl font-bold text-white mb-2">{isPermissionError ? 'Permission Denied' : 'Generation Failed'}</h3>
            {isPermissionError ? (
               <p className="text-slate-400 text-center max-w-md mb-6">Your API key is valid, but lacks permissions. Please enable the <strong>Vertex AI API</strong> in your Google Cloud project to proceed.</p>
            ) : (
               <p className="text-slate-400 text-center max-w-md mb-6">You may have hit API quota limits or the key is invalid. To continue generating, please connect your personal paid API key.</p>
            )}
            <button onClick={resetAppState} className="flex items-center gap-2 px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all shadow-xl shadow-indigo-600/30">
              <RefreshCw className="w-5 h-5" /> Try Again
            </button>
          </div>
        )}

        {(status === GenerationStatus.GENERATING_5_ASSETS || status === GenerationStatus.REVIEW_5_ASSETS) && (
          <div className="animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="text-center mb-8">
                <h2 className="text-3xl font-extrabold text-white">Step 1: Choose Your Winning Concept</h2>
                <p className="text-slate-400 mt-1">The AI has generated 5 concepts based on top market trends. Select one to continue.</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-6 mb-8">
              {designAssets.map(asset => (
                <DesignAssetCard 
                  key={asset.id} 
                  asset={asset} 
                  isSelected={selectedDesignAssetId === asset.id}
                  onSelect={handleSelectDesign}
                />
              ))}
            </div>
            {status === GenerationStatus.REVIEW_5_ASSETS && (
              <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
                  <button onClick={resetAppState} className="flex items-center justify-center gap-2 px-6 py-3 bg-slate-700 hover:bg-slate-600 text-white font-bold rounded-xl transition-all">
                      <RefreshCw className="w-5 h-5" /> Start Over
                  </button>
                  <button 
                      onClick={handleApproveAndGenerateMockups}
                      disabled={!selectedDesignAssetId}
                      className="flex items-center justify-center gap-2 px-10 py-4 bg-green-600 hover:bg-green-500 text-white font-bold rounded-xl transition-all shadow-xl shadow-green-600/20 disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                      <CheckCircle2 className="w-5 h-5" /> Generate Mockups With This Design
                  </button>
              </div>
            )}
          </div>
        )}

        {(status === GenerationStatus.GENERATING_MOCKUPS || status === GenerationStatus.COMPLETED) && (
          <div className="animate-in fade-in duration-1000">
             <div className="flex flex-col md:flex-row justify-between items-start mb-8 gap-4 border-b border-slate-800 pb-6">
                <div>
                   <h2 className="text-3xl font-extrabold text-white">Step 2: Market-Ready Assets</h2>
                   <p className="text-slate-400 mt-1">High-quality visuals optimized for e-commerce and social media.</p>
                </div>
                {status === GenerationStatus.COMPLETED && (
                  <div className="flex flex-col sm:flex-row gap-3">
                    <button 
                      onClick={handleGenerateVideoPrompt}
                      disabled={isVideoPromptGenerating}
                      className="flex items-center justify-center gap-2 px-6 py-3 bg-slate-700 hover:bg-slate-600 text-white font-bold rounded-xl transition-all shadow-lg shadow-slate-700/30 disabled:opacity-50 disabled:cursor-not-allowed whitespace-nowrap"
                    >
                      {isVideoPromptGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <FileText className="w-5 h-5" />}
                      Generate Video Script
                    </button>
                    <button 
                        onClick={handleGenerateVideo}
                        disabled={!hasApiKey || isVideoGenerating}
                        className="flex items-center justify-center gap-2 px-6 py-3 bg-rose-600 hover:bg-rose-500 text-white font-bold rounded-xl transition-all shadow-lg shadow-rose-600/30 disabled:opacity-50 disabled:cursor-not-allowed whitespace-nowrap"
                        title={!hasApiKey ? "Connect a paid API key to enable video generation" : ""}
                      >
                        {isVideoGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Film className="w-5 h-5" />}
                        Create Promo Video
                      </button>
                    <button 
                      onClick={handleDownloadAll}
                      disabled={isZipping}
                      className="flex items-center justify-center gap-2 px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all shadow-xl shadow-indigo-600/30 disabled:opacity-50"
                    >
                      {isZipping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                      Download All
                    </button>
                  </div>
                )}
             </div>

             { (isVideoGenerating || videoUrl || videoError) && (
                <div className="mb-12">
                    <h3 className="text-2xl font-bold text-white mb-4">Social Media Video</h3>
                    {isVideoGenerating && (<div className="aspect-video w-full max-w-md mx-auto bg-slate-800 rounded-xl flex flex-col items-center justify-center border border-slate-700"><Loader2 className="w-12 h-12 text-rose-500 animate-spin mb-4" /><p className="text-white font-semibold">Rendering your video...</p><p className="text-slate-400 text-sm">This may take a few minutes.</p></div>)}
                    {videoError && (<div className="aspect-video w-full max-w-md mx-auto bg-rose-500/10 rounded-xl flex flex-col items-center justify-center border border-rose-500/30 p-4"><AlertCircle className="w-12 h-12 text-rose-500 mb-4" /><p className="text-white font-semibold text-center mb-4">Video Generation Failed</p><p className="text-rose-200 text-sm text-center mb-6 break-words">{videoError}</p><button onClick={handleOpenKeySelector} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-lg transition-all text-sm"><Key className="w-4 h-4"/> Connect/Check API Key</button></div>)}
                    {videoUrl && (<div className="w-full max-w-md mx-auto"><video src={videoUrl} controls className="rounded-xl w-full aspect-[9/16] bg-black" /><a href={videoUrl} download={`promo_video_${currentSlogan.slice(0, 15)}.mp4`} className="mt-4 w-full flex items-center justify-center gap-2 px-8 py-3 bg-green-600 hover:bg-green-500 text-white font-bold rounded-xl transition-all shadow-lg shadow-green-600/30"><Download className="w-5 h-5" /> Download Video (MP4)</a></div>)}
                </div>
             )}

             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {images.map((image) => (
                  <ImageCard key={image.id} image={image} onRetry={handleRetry} />
                ))}
             </div>

             {status === GenerationStatus.COMPLETED && (
                <div className="mt-16 text-center">
                    <button onClick={resetAppState} className="px-8 py-3 rounded-full border border-slate-700 text-slate-400 hover:text-white hover:border-slate-500 transition-all text-sm font-semibold">
                      Create Another Collection
                    </button>
                </div>
             )}
          </div>
        )}
      </main>

      {isVideoPromptModalOpen && videoPrompt && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4 animate-in fade-in duration-300">
          <div className="bg-slate-800 rounded-2xl border border-slate-700 shadow-2xl w-full max-w-2xl flex flex-col">
            <div className="p-4 border-b border-slate-700 flex justify-between items-center"><div className='flex items-center gap-2'><FileText className="w-5 h-5 text-indigo-400" /><h3 className="text-lg font-bold text-white">AI Video Director Script</h3></div><button onClick={() => setIsVideoPromptModalOpen(false)} className="p-1 rounded-full hover:bg-slate-700 transition-colors"><X className="w-5 h-5 text-slate-400" /></button></div>
            <pre className="p-6 text-sm text-slate-300 overflow-y-auto max-h-[60vh] whitespace-pre-wrap font-sans bg-slate-900/50">{videoPrompt}</pre>
            <div className="p-4 border-t border-slate-700 flex justify-end"><button onClick={handleCopyPrompt} className="flex items-center gap-2 px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-lg transition-all text-sm shadow-lg shadow-indigo-500/30"><Clipboard className="w-4 h-4" />{hasCopied ? 'Copied!' : 'Copy Script'}</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect } from 'react';
import JSZip from 'jszip';
import { DESIGN_ASSET_CONFIG, PRODUCT_MOCKUP_CONFIGS, INITIAL_IMAGES, ALL_CONFIGS, NICHES, DESIGN_STYLES, COLOR_PALETTES } from './constants';
import { GeneratedImage, GenerationStatus, DesignStrategy, DesignAsset, StrategySuggestion } from './types';
import { generateMockupImage, generateDesignStrategy, generatePromoVideo, generateVideoPrompt, generateFiveDesignConcepts } from './services/geminiService';
import Header from './components/Header';
import PromptInput from './components/PromptInput';
import ImageCard from './components/ImageCard';
import DesignAssetCard from './components/DesignAssetCard';
import { CheckCircle2, RefreshCw, Download, Loader2, BrainCircuit, Key, AlertCircle, Film, ExternalLink, FileText, Clipboard, X, Wand2 } from 'lucide-react';

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const App: React.FC = () => {
  const [images, setImages] = useState<GeneratedImage[]>(INITIAL_IMAGES);
  const [designStrategy, setDesignStrategy] = useState<DesignStrategy | null>(null);
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);

  const [currentSlogan, setCurrentSlogan] = useState<string>('');
  const [currentAudience, setCurrentAudience] = useState<string>('');

  const [designAssets, setDesignAssets] = useState<DesignAsset[]>([]);
  const [selectedDesignAssetId, setSelectedDesignAssetId] = useState<string | null>(null);

  const [isZipping, setIsZipping] = useState(false);
  const [hasApiKey, setHasApiKey] = useState(false);

  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [isVideoGenerating, setIsVideoGenerating] = useState(false);
  const [videoError, setVideoError] = useState<string | null>(null);

  const [videoPrompt, setVideoPrompt] = useState<string | null>(null);
  const [isVideoPromptGenerating, setIsVideoPromptGenerating] = useState(false);
  const [isVideoPromptModalOpen, setIsVideoPromptModalOpen] = useState(false);
  const [hasCopied, setHasCopied] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      setHasApiKey(hasKey);
    };
    checkKey();
  }, []);

  const resetAppState = () => {
    setStatus(GenerationStatus.IDLE);
    setImages(INITIAL_IMAGES);
    setCurrentSlogan('');
    setCurrentAudience('');
    setDesignStrategy(null);
    setDesignAssets([]);
    setSelectedDesignAssetId(null);
    setVideoUrl(null);
    setIsVideoGenerating(false);
    setVideoError(null);
    setVideoPrompt(null);
    setIsVideoPromptGenerating(false);
    setIsVideoPromptModalOpen(false);
  };

  const handleOpenKeySelector = async () => {
    // @ts-ignore
    await window.aistudio.openSelectKey();
    setHasApiKey(true); 
  };

  const handleError = (error: any, assetId?: string) => {
    const isPermissionError = error?.message?.includes('403') || error?.message?.includes('PERMISSION_DENIED');
    const isQuotaError = !isPermissionError && (error?.message?.includes('429') || error?.message?.includes('RESOURCE_EXHAUSTED') || error?.message?.includes('API key not valid'));

    let errorMessage = error.message || 'An unknown error occurred.';
    if (isPermissionError) {
        errorMessage = "Permission Denied: Please enable the 'Vertex AI API' in your Google Cloud project.";
    } else if (isQuotaError) {
        errorMessage = 'API Quota/Key Error: Please connect a valid, paid API key.';
    }

    if (assetId) {
      setDesignAssets(prev => prev.map(asset => 
        asset.id === assetId ? { ...asset, loading: false, error: errorMessage } : asset
      ));
    }

    if (isQuotaError || isPermissionError) {
      setStatus(GenerationStatus.ERROR);
    }
  };

  const handleStartGenerationProcess = async (slogan: string, audience: string) => {
    resetAppState();
    setCurrentSlogan(slogan);
    setCurrentAudience(audience);
    setStatus(GenerationStatus.GENERATING_5_ASSETS);

    try {
      const top5Concepts = await generateFiveDesignConcepts(slogan, audience);

      const initialAssets: DesignAsset[] = top5Concepts.map((concept, index) => ({
        id: `design-${index}`,
        imageUrl: null,
        loading: true,
        error: null,
        strategy: concept
      }));
      setDesignAssets(initialAssets);

      // Generate concepts sequentially to avoid rate limiting
      for (const asset of initialAssets) {
        try {
            // The detailed strategy is now fetched in the initial call, so we pass it directly.
            const imageUrl = await generateMockupImage(DESIGN_ASSET_CONFIG.template(slogan, { designStyle: asset.strategy.designStyle } as DesignStrategy));

            setDesignAssets(prev => prev.map(a => 
              a.id === asset.id ? { ...a, loading: false, imageUrl: imageUrl, error: null } : a
            ));
        } catch (error: any) {
            handleError(error, asset.id);
        }
        await sleep(4000); // Add a delay to prevent rate limiting
      }

      setStatus(GenerationStatus.REVIEW_5_ASSETS);

    } catch (e: any) {
      handleError(e);
      setStatus(GenerationStatus.ERROR);
    }
  };

  const handleSelectDesign = (assetId: string) => {
    setSelectedDesignAssetId(assetId);
  };

  const generateSingleMockup = useCallback(async (configId: string, prompt: string, referenceImage: string) => {
    try {
      const base64Url = await generateMockupImage(prompt, referenceImage);
      setImages(prev => prev.map(img => img.configId === configId ? { ...img, loading: false, imageUrl: base64Url } : img));
    } catch (error: any) {
      const isPermissionError = error?.message?.includes('403') || error?.message?.includes('PERMISSION_DENIED');
      const isQuotaError = !isPermissionError && (error?.message?.includes('429') || error?.message?.includes('RESOURCE_EXHAUSTED') || error?.message?.includes('API key not valid'));

      let errorMessage = error.message || 'An unknown error occurred.';
      if (isPermissionError) {
          errorMessage = "Permission Denied: Enable Vertex AI API.";
      } else if (isQuotaError) {
          errorMessage = 'API Quota/Key Error: Check key.';
      }

      setImages(prev => prev.map(img => img.configId === configId ? { ...img, loading: false, error: errorMessage } : img));

      if (isQuotaError || isPermissionError) {
        setStatus(GenerationStatus.ERROR);
      }
    }
  }, []);

  const handleApproveAndGenerateMockups = async () => {
    const selectedAsset = designAssets.find(asset => asset.id === selectedDesignAssetId);
    if (!selectedAsset?.imageUrl) return;

    setStatus(GenerationStatus.GENERATING_MOCKUPS);

    // Set the first image (design asset) for the final grid
    const finalImages: GeneratedImage[] = ALL_CONFIGS.map(config => ({
      id: config.id,
      configId: config.id,
      title: config.title,
      imageUrl: config.id === DESIGN_ASSET_CONFIG.id ? selectedAsset.imageUrl : null,
      loading: config.id !== DESIGN_ASSET_CONFIG.id,
      error: null,
    }));
    setImages(finalImages);

    // Generate detailed strategy for the selected design to guide mockups
    try {
        const nicheObj = NICHES.find(n => n.id === selectedAsset.strategy.nicheId) || NICHES[0];
        const styleObj = DESIGN_STYLES.find(s => s.id === selectedAsset.strategy.styleId) || DESIGN_STYLES[0];
        const colorObj = COLOR_PALETTES.find(c => c.id === selectedAsset.strategy.colorId) || COLOR_PALETTES[0];

        const detailedStrategy = await generateDesignStrategy(currentSlogan, nicheObj.label, styleObj.context, currentAudience, colorObj.context);
        setDesignStrategy(detailedStrategy);

        // Generate mockups sequentially with a delay
        for (const config of PRODUCT_MOCKUP_CONFIGS) {
          await generateSingleMockup(config.id, config.template(currentSlogan, detailedStrategy), selectedAsset.imageUrl!);
          await sleep(4000);
        }
    } catch (e) {
      handleError(e);
      setStatus(GenerationStatus.ERROR);
    }
  };

  const handleGenerateVideo = async () => {
    if (!designStrategy || !currentSlogan) return;

    setIsVideoGenerating(true);
    setVideoUrl(null);
    setVideoError(null);

    try {
      const referenceImageIds = ['tshirt-mockup', 'hoodie-mockup', 'phonecase-mockup'];
      const referenceImages = images
        .filter(img => referenceImageIds.includes(img.configId) && img.imageUrl)
        .map(img => img.imageUrl!);

      if (referenceImages.length < 1) {
        throw new Error("Not enough successful mockups to generate a video.");
      }

      const url = await generatePromoVideo(currentSlogan, designStrategy, referenceImages);
      setVideoUrl(url);

    } catch (error: any) {
      const isPermissionError = error?.message?.includes('403') || error?.message?.includes('PERMISSION_DENIED');
      const isQuotaError = !isPermissionError && (error?.message?.includes('429') || error?.message?.includes('RESOURCE_EXHAUSTED') || error?.message?.includes('not found'));

      let videoErrorMessage = 'Video generation failed. Please try again.';
      if (isPermissionError) {
        videoErrorMessage = 'Permission Denied. Please ensure the "Vertex AI API" is enabled in your Google Cloud project to generate videos.';
      } else if (isQuotaError) {
        videoErrorMessage = 'Video generation requires a valid paid API Key with sufficient quota. Please check your key and billing status.';
      } else if (error.message) {
        videoErrorMessage = error.message;
      }
      setVideoError(videoErrorMessage);
    } finally {
      setIsVideoGenerating(false);
    }
  };

  const handleGenerateVideoPrompt = async () => {
    const selectedAsset = designAssets.find(asset => asset.id === selectedDesignAssetId);
    const niche = NICHES.find(n => n.id === selectedAsset?.strategy.nicheId)?.label || 'General';
    if (!designStrategy || !currentSlogan || !niche) return;

    const successfulMockups = images
      .filter(img => img.imageUrl && img.configId !== DESIGN_ASSET_CONFIG.id)
      .map(img => img.imageUrl!);

    if (successfulMockups.length === 0) {
      alert("Please generate some mockups before creating a video script.");
      return;
    }

    setIsVideoPromptGenerating(true);
    setVideoPrompt(null);
    try {
      const prompt = await generateVideoPrompt(currentSlogan, niche, currentAudience, designStrategy, successfulMockups);
      setVideoPrompt(prompt);
      setIsVideoPromptModalOpen(true);
    } catch(e) {
      // Simple error handling for prompt generation
      alert("Sorry, the AI Director is busy. Please try again in a moment.");
    } finally {
      setIsVideoPromptGenerating(false);
    }
  };

  const handleCopyPrompt = () => {
    if (videoPrompt) {
      navigator.clipboard.writeText(videoPrompt);
      setHasCopied(true);
      setTimeout(() => setHasCopied(false), 2000);
    }
  };

  useEffect(() => {
    const isMockupsLoading = images.filter(i => i.configId !== DESIGN_ASSET_CONFIG.id).some(img => img.loading);
    if (!isMockupsLoading && status === GenerationStatus.GENERATING_MOCKUPS) {
      setStatus(GenerationStatus.COMPLETED);
    }
  }, [images, status]);

  // FIX: Implement retry/regenerate functionality for individual mockups.
  const handleRetry = useCallback((configId: string) => {
    if (status === GenerationStatus.REVIEW_5_ASSETS) {
      alert("To retry a concept, please use the 'Start Over' button for a fresh set of concepts.");
      return;
    }

    if (configId === DESIGN_ASSET_CONFIG.id) return; // Cannot retry main asset here

    const selectedAsset = designAssets.find(asset => asset.id === selectedDesignAssetId);
    if (selectedAsset?.imageUrl && designStrategy && currentSlogan) {
      const config = PRODUCT_MOCKUP_CONFIGS.find(c => c.id === configId);
      if (config) {
        setImages(prev => prev.map(img => 
          img.configId === configId ? { ...img, loading: true, error: null } : img
        ));
        generateSingleMockup(config.id, config.template(currentSlogan, designStrategy), selectedAsset.imageUrl);
      }
    }
  }, [status, designAssets, selectedDesignAssetId, designStrategy, currentSlogan, generateSingleMockup]);


  const handleDownloadAll = async () => {
    setIsZipping(true);
    const zip = new JSZip();
    const folder = zip.folder(`pod-assets-${Date.now()}`);
    if (folder) {
      const sortedImages = [...images].sort((a, b) => {
        const indexA = ALL_CONFIGS.findIndex(c => c.id === a.configId);
        const indexB = ALL_CONFIGS.findIndex(c => c.id === b.configId);
        return indexA - indexB;
      });

      sortedImages.forEach(img => {
        if (img.imageUrl) {
          const sanitizedTitle = img.title
            .replace(/\s/g, '_')
            .replace(/[&/]/g, '-')
            .replace(/[()]/g, '');
          folder.file(`${sanitizedTitle}.png`, img.imageUrl.split(',')[1], { base64: true });
        }
      });
      if (videoUrl) {
        try {
          const response = await fetch(videoUrl);
          const blob = await response.blob();
          folder.file('promo_video.mp4', blob);
        } catch (e) {
          console.error("Could not add video to zip", e);
        }
      }
      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `pod_assets_${currentSlogan.replace(/\s/g, '_').slice(0, 15)}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
    setIsZipping(false);
  };

  const getStatusText = () => {
    if (status === GenerationStatus.GENERATING_5_ASSETS) return "AI is generating 5 concepts...";
    if (status === GenerationStatus.ANALYZING) return "AI Strategist is thinking...";
    return "Processing...";
  }

  const firstError = images.find(img => img.error)?.error;
  const isPermissionError = firstError?.includes('Permission Denied');
  const isGeneratingAnything = status !== GenerationStatus.IDLE && status !== GenerationStatus.COMPLETED && status !== GenerationStatus.ERROR;

  return (
    <div className="min-h-screen pb-20 bg-slate-900">
      <Header />

      {!hasApiKey && (
        <div className="max-w-5xl mx-auto px-4 mt-6">
          <div className="bg-amber-500/10 border border-amber-500/30 rounded-xl p-4 flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <AlertCircle className="w-5 h-5 text-amber-500" />
              <div>
                <p className="text-amber-200 text-sm font-semibold">High Quality & No Quota Limits</p>
                <p className="text-amber-200/60 text-xs">Connect your own paid API key to unlock high-quality models.</p>
              </div>
            </div>
            <button 
              onClick={handleOpenKeySelector}
              className="flex items-center gap-2 px-4 py-2 bg-amber-500 hover:bg-amber-400 text-slate-900 font-bold rounded-lg transition-all text-sm whitespace-nowrap"
            >
              <Key className="w-4 h-4" />
              Connect Paid Key
            </button>
          </div>
          <p className="text-slate-500 text-[10px] mt-2 px-2">
            Requires a paid GCP project key. Learn more at <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noopener noreferrer" className="underline">ai.google.dev/gemini-api/docs/billing</a>
          </p>
        </div>
      )}

      <div className="transition-all duration-500 relative">
         <PromptInput 
            onGenerate={handleStartGenerationProcess}
            isGenerating={isGeneratingAnything}
            statusText={getStatusText()}
         />
      </div>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 mt-12">
        {status === GenerationStatus.ERROR && (
          <div className="flex flex-col items-center justify-center p-12 bg-slate-800 rounded-3xl border border-rose-500/30 mb-8">
            <AlertCircle className="w-16 h-16 text-rose-500 mb-4" />
            <h3 className="text-xl font-bold text-white mb-2">{isPermissionError ? 'Permission Denied' : 'Generation Failed'}</h3>
            {isPermissionError ? (
               <p className="text-slate-400 text-center max-w-md mb-6">Your API key is valid, but lacks permissions. Please enable the <strong>Vertex AI API</strong> in your Google Cloud project to proceed.</p>
            ) : (
               <p className="text-slate-400 text-center max-w-md mb-6">You may have hit API quota limits or the key is invalid. To continue generating, please connect your personal paid API key.</p>
            )}
            <button onClick={resetAppState} className="flex items-center gap-2 px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all shadow-xl shadow-indigo-600/30">
              <RefreshCw className="w-5 h-5" /> Try Again
            </button>
          </div>
        )}

        {(status === GenerationStatus.GENERATING_5_ASSETS || status === GenerationStatus.REVIEW_5_ASSETS) && (
          <div className="animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="text-center mb-8">
                <h2 className="text-3xl font-extrabold text-white">Step 1: Choose Your Winning Concept</h2>
                <p className="text-slate-400 mt-1">The AI has generated 5 concepts based on top market trends. Select one to continue.</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-6 mb-8">
              {designAssets.map(asset => (
                <DesignAssetCard 
                  key={asset.id} 
                  asset={asset} 
                  isSelected={selectedDesignAssetId === asset.id}
                  onSelect={handleSelectDesign}
                />
              ))}
            </div>
            {status === GenerationStatus.REVIEW_5_ASSETS && (
              <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
                  <button onClick={resetAppState} className="flex items-center justify-center gap-2 px-6 py-3 bg-slate-700 hover:bg-slate-600 text-white font-bold rounded-xl transition-all">
                      <RefreshCw className="w-5 h-5" /> Start Over
                  </button>
                  <button 
                      onClick={handleApproveAndGenerateMockups}
                      disabled={!selectedDesignAssetId}
                      className="flex items-center justify-center gap-2 px-10 py-4 bg-green-600 hover:bg-green-500 text-white font-bold rounded-xl transition-all shadow-xl shadow-green-600/20 disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                      <CheckCircle2 className="w-5 h-5" /> Generate Mockups With This Design
                  </button>
              </div>
            )}
          </div>
        )}

        {(status === GenerationStatus.GENERATING_MOCKUPS || status === GenerationStatus.COMPLETED) && (
          <div className="animate-in fade-in duration-1000">
             <div className="flex flex-col md:flex-row justify-between items-start mb-8 gap-4 border-b border-slate-800 pb-6">
                <div>
                   <h2 className="text-3xl font-extrabold text-white">Step 2: Market-Ready Assets</h2>
                   <p className="text-slate-400 mt-1">High-quality visuals optimized for e-commerce and social media.</p>
                </div>
                {status === GenerationStatus.COMPLETED && (
                  <div className="flex flex-col sm:flex-row gap-3">
                    <button 
                      onClick={handleGenerateVideoPrompt}
                      disabled={isVideoPromptGenerating}
                      className="flex items-center justify-center gap-2 px-6 py-3 bg-slate-700 hover:bg-slate-600 text-white font-bold rounded-xl transition-all shadow-lg shadow-slate-700/30 disabled:opacity-50 disabled:cursor-not-allowed whitespace-nowrap"
                    >
                      {isVideoPromptGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <FileText className="w-5 h-5" />}
                      Generate Video Script
                    </button>
                    <button 
                        onClick={handleGenerateVideo}
                        disabled={!hasApiKey || isVideoGenerating}
                        className="flex items-center justify-center gap-2 px-6 py-3 bg-rose-600 hover:bg-rose-500 text-white font-bold rounded-xl transition-all shadow-lg shadow-rose-600/30 disabled:opacity-50 disabled:cursor-not-allowed whitespace-nowrap"
                        title={!hasApiKey ? "Connect a paid API key to enable video generation" : ""}
                      >
                        {isVideoGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Film className="w-5 h-5" />}
                        Create Promo Video
                      </button>
                    <button 
                      onClick={handleDownloadAll}
                      disabled={isZipping}
                      className="flex items-center justify-center gap-2 px-8 py-3 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all shadow-xl shadow-indigo-600/30 disabled:opacity-50"
                    >
                      {isZipping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Download className="w-5 h-5" />}
                      Download All
                    </button>
                  </div>
                )}
             </div>

             { (isVideoGenerating || videoUrl || videoError) && (
                <div className="mb-12">
                    <h3 className="text-2xl font-bold text-white mb-4">Social Media Video</h3>
                    {isVideoGenerating && (<div className="aspect-video w-full max-w-md mx-auto bg-slate-800 rounded-xl flex flex-col items-center justify-center border border-slate-700"><Loader2 className="w-12 h-12 text-rose-500 animate-spin mb-4" /><p className="text-white font-semibold">Rendering your video...</p><p className="text-slate-400 text-sm">This may take a few minutes.</p></div>)}
                    {videoError && (<div className="aspect-video w-full max-w-md mx-auto bg-rose-500/10 rounded-xl flex flex-col items-center justify-center border border-rose-500/30 p-4"><AlertCircle className="w-12 h-12 text-rose-500 mb-4" /><p className="text-white font-semibold text-center mb-4">Video Generation Failed</p><p className="text-rose-200 text-sm text-center mb-6 break-words">{videoError}</p><button onClick={handleOpenKeySelector} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-lg transition-all text-sm"><Key className="w-4 h-4"/> Connect/Check API Key</button></div>)}
                    {videoUrl && (<div className="w-full max-w-md mx-auto"><video src={videoUrl} controls className="rounded-xl w-full aspect-[9/16] bg-black" /><a href={videoUrl} download={`promo_video_${currentSlogan.slice(0, 15)}.mp4`} className="mt-4 w-full flex items-center justify-center gap-2 px-8 py-3 bg-green-600 hover:bg-green-500 text-white font-bold rounded-xl transition-all shadow-lg shadow-green-600/30"><Download className="w-5 h-5" /> Download Video (MP4)</a></div>)}
                </div>
             )}

             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {images.map((image) => (
                  <ImageCard key={image.id} image={image} onRetry={handleRetry} />
                ))}
             </div>

             {status === GenerationStatus.COMPLETED && (
                <div className="mt-16 text-center">
                    <button onClick={resetAppState} className="px-8 py-3 rounded-full border border-slate-700 text-slate-400 hover:text-white hover:border-slate-500 transition-all text-sm font-semibold">
                      Create Another Collection
                    </button>
                </div>
             )}
          </div>
        )}
      </main>

      {isVideoPromptModalOpen && videoPrompt && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4 animate-in fade-in duration-300">
          <div className="bg-slate-800 rounded-2xl border border-slate-700 shadow-2xl w-full max-w-2xl flex flex-col">
            <div className="p-4 border-b border-slate-700 flex justify-between items-center"><div className='flex items-center gap-2'><FileText className="w-5 h-5 text-indigo-400" /><h3 className="text-lg font-bold text-white">AI Video Director Script</h3></div><button onClick={() => setIsVideoPromptModalOpen(false)} className="p-1 rounded-full hover:bg-slate-700 transition-colors"><X className="w-5 h-5 text-slate-400" /></button></div>
            <pre className="p-6 text-sm text-slate-300 overflow-y-auto max-h-[60vh] whitespace-pre-wrap font-sans bg-slate-900/50">{videoPrompt}</pre>
            <div className="p-4 border-t border-slate-700 flex justify-end"><button onClick={handleCopyPrompt} className="flex items-center gap-2 px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-lg transition-all text-sm shadow-lg shadow-indigo-500/30"><Clipboard className="w-4 h-4" />{hasCopied ? 'Copied!' : 'Copy Script'}</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Loader2, Sparkles, Users, BrainCircuit, Palette, Film } from 'lucide-react';

interface PromptInputProps {
  onGenerate: (slogan: string, audience: string) => void;
  isGenerating: boolean;
  statusText?: string;
}

const PromptInput: React.FC<PromptInputProps> = ({ 
  onGenerate, 
  isGenerating, 
  statusText,
}) => {
  const [slogan, setSlogan] = useState('');
  const [audience, setAudience] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (slogan.trim()) {
      onGenerate(slogan, audience);
    }
  };

  return (
    <div className="w-full max-w-5xl mx-auto -mt-6 relative z-10 px-4">
      <form onSubmit={handleSubmit} className="bg-slate-800 p-6 rounded-2xl shadow-2xl border border-slate-700 flex flex-col gap-5">

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Who is this for? (Audience)</label>
                <div className="relative">
                    <input
                        type="text"
                        value={audience}
                        onChange={(e) => setAudience(e.target.value)}
                        placeholder="e.g., Cat Lovers, Proud Teachers, Gen Z..."
                        className="w-full bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm pl-10"
                        disabled={isGenerating}
                    />
                    <Users className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                </div>
            </div>

            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Slogan / Text on Shirt</label>
                <input
                    type="text"
                    value={slogan}
                    onChange={(e) => setSlogan(e.target.value)}
                    placeholder="e.g., 'Not all who wander are lost'"
                    className="w-full bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-medium"
                    disabled={isGenerating}
                />
            </div>
        </div>

        {/* Submit Button */}
        <button
          type="submit"
          disabled={isGenerating || !slogan.trim()}
          className="w-full font-bold px-8 py-4 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2 bg-gradient-to-r from-indigo-600 to-indigo-500 hover:from-indigo-500 hover:to-indigo-400 text-white shadow-indigo-500/30 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {isGenerating ? (
            <>
              <Loader2 className="w-5 h-5 animate-spin" />
              <span>{statusText || 'Brainstorming Market Strategy...'}</span>
            </>
          ) : (
            <>
              <Sparkles className="w-5 h-5" />
              <span>Generate Viral Design & Mockups</span>
            </>
          )}
        </button>
      </form>
      <div className="text-center mt-4 text-slate-500 text-xs flex items-center justify-center gap-3">
        <span className="flex items-center gap-1"><BrainCircuit className="w-3 h-3" /> Strategy: Gemini 3 Flash</span>
        <span className="flex items-center gap-1"><Palette className="w-3 h-3" /> Image: Gemini Flash Image</span>
        <span className="flex items-center gap-1"><Film className="w-3 h-3" /> Video: Veo</span>
      </div>
    </div>
  );
};

export default PromptInput;

import { GoogleGenAI, Type, VideoGenerationReferenceImage, VideoGenerationReferenceType } from "@google/genai";
import { DesignStrategy, StrategySuggestion } from "../types";
import { NICHES, DESIGN_STYLES, COLOR_PALETTES } from "../constants";

export const generateFiveDesignConcepts = async (slogan: string, audience: string): Promise<StrategySuggestion[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const nicheOptions = NICHES.map(n => `ID: "${n.id}", Label: "${n.label}"`).join('\n');
    const styleOptions = DESIGN_STYLES.map(s => `ID: "${s.id}", Label: "${s.label}", Context: "${s.context}"`).join('\n');
    const colorOptions = COLOR_PALETTES.map(c => `ID: "${c.id}", Label: "${c.label}", Context: "${c.context}"`).join('\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are an expert Print-on-Demand (POD) market trend analyst and a creative director.
      Your task is to analyze the provided slogan and target audience, then generate the top 3 most commercially viable and distinct design concepts.
      For each concept, you must provide both a high-level strategy and a specific creative direction.

      **Slogan:** "${slogan}"
      **Target Audience:** "${audience || 'General public'}"

      **Available Options (You MUST return one ID from each category for each of the 3 strategies):**

      **Target Niches:**
      ${nicheOptions}

      **Visual Trends:**
      ${styleOptions}

      **Color Palettes:**
      ${colorOptions}

      **Instructions:**
      1.  Analyze the slogan and audience to identify key themes and vibes.
      2.  Cross-reference this with your knowledge of best-selling POD trends.
      3.  Generate an array of 3 unique and diverse concept objects.
      4.  For each object, select the single best ID from the Niches, Visual Trends, and Color Palettes lists.
      5.  Provide a short, catchy 'title' (e.g., "Retro Gamer Vibe", "Minimalist Zen").
      6.  Provide a brief 'rationale' explaining why this strategy will sell.
      7.  Crucially, for each object, also provide a detailed 'designStyle' object containing specific creative direction: 'typography', 'artStyle', 'colors', and 'mood'. This should be detailed enough to guide an image generation AI.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING, description: "A short, catchy title for the strategy." },
              nicheId: { type: Type.STRING },
              styleId: { type: Type.STRING },
              colorId: { type: Type.STRING },
              rationale: { type: Type.STRING, description: "Your reasoning for choosing this strategy, citing market trends." },
              designStyle: {
                type: Type.OBJECT,
                properties: {
                  typography: { type: Type.STRING },
                  artStyle: { type: Type.STRING },
                  colors: { type: Type.STRING },
                  mood: { type: Type.STRING },
                },
                required: ["typography", "artStyle", "colors", "mood"]
              }
            },
            required: ["title", "nicheId", "styleId", "colorId", "rationale", "designStyle"]
          }
        }
      }
    });

    if (response.text) {
      const suggestions = JSON.parse(response.text) as StrategySuggestion[];
      if (suggestions.length > 3) return suggestions.slice(0, 3);
      return suggestions;
    }
    throw new Error("No strategy suggestion generated");
  } catch (error) {
    console.error("Error suggesting strategies:", error);
    throw error;
  }
};

export const generateDesignStrategy = async (
  slogan: string, 
  niche: string, 
  styleContext: string,
  targetAudience: string,
  colorContext: string
): Promise<DesignStrategy> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a world-class Print-on-Demand (POD) and Social Media Strategist. 
      Analyze the slogan: "${slogan}" for the niche: "${niche}".
      Target Audience: ${targetAudience || 'General public'}.
      Required Style: ${styleContext}.
      Required Color Palette: ${colorContext}.

      Goal: Create a design and marketing strategy that is commercially viral on platforms like Redbubble, Etsy, and TikTok.

      Requirements:
      1. Design Style: Define typography, art style, colors, and mood.
      2. Mockups: Suggest environments for various physical products.
      3. Video: Suggest a style for a short promo video (music, visual style, transitions).
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            designStyle: {
              type: Type.OBJECT,
              properties: {
                typography: { type: Type.STRING }, artStyle: { type: Type.STRING }, colors: { type: Type.STRING }, mood: { type: Type.STRING },
              }, required: ["typography", "artStyle", "colors", "mood"]
            },
            mockups: {
              type: Type.OBJECT,
              properties: {
                tshirt: { type: Type.OBJECT, properties: { model: { type: Type.STRING }, environment: { type: Type.STRING }, lighting: { type: Type.STRING }, } },
                mug: { type: Type.OBJECT, properties: { setting: { type: Type.STRING }, props: { type: Type.STRING }, } },
                sticker: { type: Type.OBJECT, properties: { surface: { type: Type.STRING }, lighting: { type: Type.STRING }, } },
                phoneCase: { type: Type.OBJECT, properties: { surface: { type: Type.STRING }, props: { type: Type.STRING }, } },
                poster: { type: Type.OBJECT, properties: { room: { type: Type.STRING }, style: { type: Type.STRING }, } },
                cap: { type: Type.OBJECT, properties: { style: { type: Type.STRING }, setting: { type: Type.STRING }, } },
                pillow: { type: Type.OBJECT, properties: { setting: { type: Type.STRING }, colors: { type: Type.STRING }, } },
                composite: { type: Type.OBJECT, properties: { arrangement: { type: Type.STRING }, theme: { type: Type.STRING }, } },
                video: { type: Type.OBJECT, properties: { music: { type: Type.STRING }, style: { type: Type.STRING }, transitions: { type: Type.STRING }, } }
              }
            }
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as DesignStrategy;
    }
    throw new Error("No strategy generated");
  } catch (error) {
    console.error("Error generating strategy:", error);
    throw error;
  }
};

export const generateMockupImage = async (prompt: string, referenceImageBase64?: string | null): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const parts: any[] = [{ text: prompt }];
    if (referenceImageBase64) {
      const base64Data = referenceImageBase64.replace(/^data:image\/\w+;base64,/, "");
      parts.push({
        inlineData: { mimeType: 'image/png', data: base64Data }
      });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: parts },
      config: { imageConfig: { aspectRatio: "1:1" } }
    });

    const candidates = response.candidates;
    if (!candidates || candidates.length === 0) throw new Error("No image generated.");

    const imagePart = candidates[0].content.parts.find(p => p.inlineData);
    if (!imagePart?.inlineData?.data) throw new Error("Missing image data.");

    return `data:image/png;base64,${imagePart.inlineData.data}`;
  } catch (error: any) {
    console.error("Error generating image:", error);
    throw error;
  }
};

export const generatePromoVideo = async (slogan: string, strategy: DesignStrategy, referenceImagesBase64: string[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const referenceImagesPayload: VideoGenerationReferenceImage[] = referenceImagesBase64
      .slice(0, 3) // Use up to 3 images as per API limitation
      .map(b64 => ({
        image: {
          imageBytes: b64.replace(/^data:image\/\w+;base64,/, ""),
          mimeType: 'image/png',
        },
        referenceType: VideoGenerationReferenceType.ASSET,
      }));

    if (referenceImagesPayload.length === 0) {
        throw new Error("No valid reference images provided for video generation.");
    }

    const videoCtx = strategy.mockups.video || { music: "upbeat electronic", style: "fast-paced", transitions: "quick cuts" };

    const prompt = `Create a short, dynamic, promotional video for a new product line with the slogan "${slogan}". 
    Video Style: ${videoCtx.style}, with ${videoCtx.transitions}. 
    Music style suggestion: ${videoCtx.music}.
    Showcase the product designs from the reference images in a trendy style suitable for TikTok or YouTube Shorts.`;

    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-generate-preview',
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        referenceImages: referenceImagesPayload,
        resolution: '720p',
        aspectRatio: '9:16' // Vertical for social media
      }
    });

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000)); // Poll every 10 seconds
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
      throw new Error("Video generation completed but no download link was found.");
    }

    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    if (!response.ok) {
        throw new Error(`Failed to download video: ${response.statusText}`);
    }
    const blob = await response.blob();
    return URL.createObjectURL(blob);

  } catch (error) {
    console.error("Error generating video:", error);
    throw error;
  }
};

export const generateVideoPrompt = async (
  slogan: string,
  niche: string,
  targetAudience: string,
  strategy: DesignStrategy,
  imageUrls: string[]
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const textPart = {
      text: `
        You are a creative director specializing in viral social media ads for e-commerce brands.
        Your task is to create a detailed video script and shot list for a 15-second promotional video, based on the provided product mockup images. This script will be used as a prompt for another video generation AI.

        **Analyze the provided images and follow these instructions:**

        **Brand & Design DNA:**
        - **Slogan:** "${slogan}"
        - **Target Audience:** ${targetAudience || 'General public'}
        - **Niche:** ${niche}
        - **Overall Mood:** ${strategy.designStyle.mood}
        - **Art Style & Colors:** Your description must reflect the visual style and colors present in the attached images.

        **Requirements for the script:**
        - **Structure:** Provide a scene-by-scene breakdown (e.g., ### Scene 1).
        - **Timestamps:** Suggest approximate timings for each scene (e.g., 0-3s).
        - **Visuals:** Describe the camera shot and action for each scene. **Crucially, your descriptions must be based on the content of the provided mockup images.** For example, instead of "a person wearing a t-shirt", describe the scene from the image: "A stylish young man in a bustling city street, golden hour lighting highlighting the texture of the black t-shirt."
        - **On-Screen Text:** Suggest any text overlays. The main slogan should be featured prominently.
        - **Audio:** Suggest a style of trending audio/music and sound effects (e.g., "*whoosh*," "*click*").
        - **Output Format:** Use Markdown for clear formatting. The final output should be a complete, ready-to-use prompt.
      `
    };

    const imageParts = imageUrls.map(url => {
      const base64Data = url.replace(/^data:image\/\w+;base64,/, "");
      return { inlineData: { mimeType: 'image/png', data: base64Data } };
    });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: [textPart, ...imageParts] },
    });

    if (response.text) {
      return response.text;
    }
    throw new Error("No video prompt generated");
  } catch (error) {
    console.error("Error generating video prompt:", error);
    throw error;
  }
};

import React, { useState, useCallback, useEffect } from 'react';
import JSZip from 'jszip';
import { DESIGN_ASSET_CONFIG, PRODUCT_MOCKUP_CONFIGS, INITIAL_IMAGES, ALL_CONFIGS, NICHES, DESIGN_STYLES, COLOR_PALETTES } from './constants';
import { GeneratedImage, GenerationStatus, DesignStrategy, DesignAsset, StrategySuggestion } from './types';
import { generateMockupImage, generateDesignStrategy, generatePromoVideo, generateVideoPrompt, generateFiveDesignConcepts } from './services/geminiService';
import Header from './components/Header';
import PromptInput from './components/PromptInput';
import ImageCard from './components/ImageCard';
import DesignAssetCard from './components/DesignAssetCard';
import { CheckCircle2, RefreshCw, Download, Loader2, BrainCircuit, Key, AlertCircle, Film, ExternalLink, FileText, Clipboard, X, Wand2 } from 'lucide-react';

const sleep = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

const App: React.FC = () => {
  const [images, setImages] = useState<GeneratedImage[]>(INITIAL_IMAGES);
  const [designStrategy, setDesignStrategy] = useState<DesignStrategy | null>(null);
  const [status, setStatus] = useState<GenerationStatus>(GenerationStatus.IDLE);

  const [currentSlogan, setCurrentSlogan] = useState<string>('');
  const [currentAudience, setCurrentAudience] = useState<string>('');

  const [designAssets, setDesignAssets] = useState<DesignAsset[]>([]);
  const [selectedDesignAssetId, setSelectedDesignAssetId] = useState<string | null>(null);

  const [isZipping, setIsZipping] = useState(false);
  const [hasApiKey, setHasApiKey] = useState(false);

  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [isVideoGenerating, setIsVideoGenerating] = useState(false);
  const [videoError, setVideoError] = useState<string | null>(null);

  const [videoPrompt, setVideoPrompt] = useState<string | null>(null);
  const [isVideoPromptGenerating, setIsVideoPromptGenerating] = useState(false);
  const [isVideoPromptModalOpen, setIsVideoPromptModalOpen] = useState(false);
  const [hasCopied, setHasCopied] = useState(false);

  useEffect(() => {
    const checkKey = async () => {
      // @ts-ignore
      const hasKey = await window.aistudio.hasSelectedApiKey();
      setHasApiKey(hasKey);
    };
    checkKey();
  }, []);

  const resetAppState = () => {
    setStatus(GenerationStatus.IDLE);
    setImages(INITIAL_IMAGES);
    setCurrentSlogan('');
    setCurrentAudience('');
    setDesignStrategy(null);
    setDesignAssets([]);
    setSelectedDesignAssetId(null);
    setVideoUrl(null);
    setIsVideoGenerating(false);
    setVideoError(null);
    setVideoPrompt(null);
    setIsVideoPromptGenerating(false);
    setIsVideoPromptModalOpen(false);
  };

  const handleOpenKeySelector = async () => {
    // @ts-ignore
    await window.aistudio.openSelectKey();
    setHasApiKey(true); 
  };

  const handleError = (error: any, assetId?: string) => {
    const isPermissionError = error?.message?.includes('403') || error?.message?.includes('PERMISSION_DENIED');
    const isQuotaError = !isPermissionError && (error?.message?.includes('429') || error?.message?.includes('RESOURCE_EXHAUSTED') || error?.message?.includes('API key not valid'));

    let errorMessage = error.message || 'An unknown error occurred.';
    if (isPermissionError) {
        errorMessage = "Permission Denied: Please enable the 'Vertex AI API' in your Google Cloud project.";
    } else if (isQuotaError) {
        errorMessage = 'API Quota/Key Error: Please connect a valid, paid API key.';
    }

    if (assetId) {
      setDesignAssets(prev => prev.map(asset => 
        asset.id === assetId ? { ...asset, loading: false, error: errorMessage } : asset
      ));
    }

    if (isQuotaError || isPermissionError) {
      setStatus(GenerationStatus.ERROR);
    }
  };

  const handleStartGenerationProcess = async (slogan: string, audience: string) => {
    resetAppState();
    setCurrentSlogan(slogan);
    setCurrentAudience(audience);
    setStatus(GenerationStatus.GENERATING_5_ASSETS);

    try {
      const topConcepts = await generateFiveDesignConcepts(slogan, audience);

      const initialAssets: DesignAsset[] = topConcepts.map((concept, index) => ({
        id: `design-${index}`,
        imageUrl: null,
        loading: true,
        error: null,
        strategy: concept
      }));
      setDesignAssets(initialAssets);

      // Generate concepts sequentially to avoid rate limiting
      for (const asset of initialAssets) {
        try {
            // The detailed strategy is now fetched in the initial call, so we pass it directly.
            const imageUrl = await generateMockupImage(DESIGN_ASSET_CONFIG.template(slogan, { designStyle: asset.strategy.designStyle } as DesignStrategy));

            setDesignAssets(prev => prev.map(a => 
              a.id === asset.id ? { ...a, loading: false, imageUrl: imageUrl, error: null } : a
            ));
        } catch (error: any) {
            handleError(error, asset.id);
        }
        await sleep(5000); // Add a delay to prevent rate limiting
      }

      setStatus(GenerationStatus.REVIEW_5_ASSETS);

    } catch (e: any) {
      handleError(e);
      setStatus(GenerationStatus.ERROR);
    }
  };

  const handleSelectDesign = (assetId: string) => {
    setSelectedDesignAssetId(assetId);
  };

  const generateSingleMockup = useCallback(async (configId: string, prompt: string, referenceImage: string) => {
    try {
      const base64Url = await generateMockupImage(prompt, referenceImage);
      setImages(prev => prev.map(img => img.configId === configId ? { ...img, loading: false, imageUrl: base64Url } : img));
    } catch (error: any) {
      const isPermissionError = error?.message?.includes('403') || error?.message?.includes('PERMISSION_DENIED');
      const isQuotaError = !isPermissionError && (error?.message?.includes('429') || error?.message?.includes('RESOURCE_EXHAUSTED') || error?.message?.includes('API key not valid'));

      let errorMessage = error.message || 'An unknown error occurred.';
      if (isPermissionError) {
          errorMessage = "Permission Denied: Enable Vertex AI API.";
      } else if (isQuotaError) {
          errorMessage = 'API Quota/Key Error: Check key.';
      }

      setImages(prev => prev.map(img => img.configId === configId ? { ...img, loading: false, error: errorMessage } : img));

      if (isQuotaError || isPermissionError) {
        setStatus(GenerationStatus.ERROR);
      }
    }
  }, []);

  const handleApproveAndGenerateMockups = async () => {
    const selectedAsset = designAssets.find(asset => asset.id === selectedDesignAssetId);
    if (!selectedAsset?.imageUrl) return;

    setStatus(GenerationStatus.GENERATING_MOCKUPS);

    // Set the first image (design asset) for the final grid
    const finalImages: GeneratedImage[] = ALL_CONFIGS.map(config => ({
      id: config.id,
      configId: config.id,
      title: config.title,
      imageUrl: config.id === DESIGN_ASSET_CONFIG.id ? selectedAsset.imageUrl : null,
      loading: config.id !== DESIGN_ASSET_CONFIG.id,
      error: null,
    }));
    setImages(finalImages);

    // Generate detailed strategy for the selected design to guide mockups
    try {
        const nicheObj = NICHES.find(n => n.id === selectedAsset.strategy.nicheId) || NICHES[0];
        const styleObj = DESIGN_STYLES.find(s => s.id === selectedAsset.strategy.styleId) || DESIGN_STYLES[0];
        const colorObj = COLOR_PALETTES.find(c => c.id === selectedAsset.strategy.colorId) || COLOR_PALETTES[0];

        const detailedStrategy = await generateDesignStrategy(currentSlogan, nicheObj.label, styleObj.context, currentAudience, colorObj.context);
        setDesignStrategy(detailedStrategy);

        // Generate mockups sequentially with a delay
        for (const config of PRODUCT_MOCKUP_CONFIGS) {
          await generateSingleMockup(config.id, config.template(currentSlogan, detailedStrategy), selectedAsset.imageUrl!);
          await sleep(5000);
        }
    } catch (e) {
      handleError(e);
      setStatus(GenerationStatus.ERROR);
    }
  };

  const handleGenerateVideo = async () => {
    if (!designStrategy || !currentSlogan) return;

    setIsVideoGenerating(true);
    setVideoUrl(null);
    setVideoError(null);

    try {
      const referenceImageIds = ['tshirt-mockup', 'hoodie-mockup', 'phonecase-mockup'];
      const referenceImages = images
        .filter(img => referenceImageIds.includes(img.configId) && img.imageUrl)
        .map(img => img.imageUrl!);

      if (referenceImages.length < 1) {
        throw new Error("Not enough successful mockups to generate a video.");
      }

      const url = await generatePromoVideo(currentSlogan, designStrategy, referenceImages);
      setVideoUrl(url);

    } catch (error: any) {
      const isPermissionError = error?.message?.includes('403') || error?.message?.includes('PERMISSION_DENIED');
      const isQuotaError = !isPermissionError && (error?.message?.includes('429') || error?.message?.includes('RESOURCE_EXHAUSTED') || error?.message?.includes('not found'));

      let videoErrorMessage = 'Video generation failed. Please try again.';
      if (isPermissionError) {
        videoErrorMessage = 'Permission Denied. Please ensure the "Vertex AI API" is enabled in your Google Cloud project to generate videos.';
      } else if (isQuotaError) {
        videoErrorMessage = 'Video generation requires a valid paid API Key with sufficient quota. Please check your key and billing status.';
      } else if (error.message) {
        videoErrorMessage = error.message;
      }
      setVideoError(videoErrorMessage);
    } finally {
      setIsVideoGenerating(false);
    }
  };

  const handleGenerateVideoPrompt = async () => {
    const selectedAsset = designAssets.find(asset => asset.id === selectedDesignAssetId);
    const niche = NICHES.find(n => n.id === selectedAsset?.strategy.nicheId)?.label || 'General';
    if (!designStrategy || !currentSlogan || !niche) return;

    const successfulMockups = images
      .filter(img => img.imageUrl && img.configId !== DESIGN_ASSET_CONFIG.id)
      .map(img => img.imageUrl!);

    if (successfulMockups.length === 0) {
      alert("Please generate some mockups before creating a video script.");
      return;
    }

    setIsVideoPromptGenerating(true);
    setVideoPrompt(null);
    try {
      const prompt = await generateVideoPrompt(currentSlogan, niche, currentAudience, designStrategy, successfulMockups);
      setVideoPrompt(prompt);
      setIsVideoPromptModalOpen(true);
    } catch(e) {
      // Simple error handling for prompt generation
      alert("Sorry, the AI Director is busy. Please try again in a moment.");
    } finally {
      setIsVideoPromptGenerating(false);
    }
  };

  const handleCopyPrompt = () => {
    if (videoPrompt) {
      navigator.clipboard.writeText(videoPrompt);
      setHasCopied(true);
      setTimeout(() => setHasCopied(false), 2000);
    }
  };

  useEffect(() => {
    const isMockupsLoading = images.filter(i => i.configId !== DESIGN_ASSET_CONFIG.id).some(img => img.loading);
    if (!isMockupsLoading && status === GenerationStatus.GENERATING_MOCKUPS) {
      setStatus(GenerationStatus.COMPLETED);
    }
  }, [images, status]);

  // FIX: Implement retry/regenerate functionality for individual mockups.
  const handleRetry = useCallback((configId: string) => {
    if (status === GenerationStatus.REVIEW_5_ASSETS) {
      alert("To retry a concept, please use the 'Start Over' button for a fresh set of concepts.");
      return;
    }

    if (configId === DESIGN_ASSET_CONFIG.id) return; // Cannot retry main asset here

    const selectedAsset = designAssets.find(asset => asset.id === selectedDesignAssetId);
    if (selectedAsset?.imageUrl && designStrategy && currentSlogan) {
      const config = PRODUCT_MOCKUP_CONFIGS.find(c => c.id === configId);
      if (config) {
        setImages(prev => prev.map(img => 
          img.configId === configId ? { ...img, loading: true, error: null } : img
        ));
        generateSingleMockup(config.id, config.template(currentSlogan, designStrategy), selectedAsset.imageUrl);
      }
    }
  }, [status, designAssets, selectedDesignAssetId, designStrategy, currentSlogan, generateSingleMockup]);


  const handleDownloadAll = async () => {
    setIsZipping(true);
    const zip = new JSZip();
    const folder = zip.folder(`pod-assets-${Date.now()}`);
    if (folder) {
      const sortedImages = [...images].sort((a, b) => {
        const indexA = ALL_CONFIGS.findIndex(c => c.id === a.configId);
        const indexB = ALL_CONFIGS.findIndex(c => c.id === b.configId);
        return indexA - indexB;
      });

      sortedImages.forEach(img => {
        if (img.imageUrl) {
          const sanitizedTitle = img.title
            .replace(/\s/g, '_')
            .replace(/[&/]/g, '-')
            .replace(/[()]/g, '');
          folder.file(`${sanitizedTitle}.png`, img.imageUrl.split(',')[1], { base64: true });
        }
      });
      if (videoUrl) {
        try {
          const response = await fetch(videoUrl);
          const blob = await response.blob();
          folder.file('promo_video.mp4', blob);
        } catch (e) {
          console.error("Could not add video to zip", e);
        }
      }
      const content = await zip.generateAsync({ type: 'blob' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(content);
      link.download = `pod_assets_${currentSlogan.replace(/\s/g, '_').slice(0, 15)}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
    setIsZipping(false);
  };

  const getStatusText = () => {
    if (status === GenerationStatus.GENERATING_5_ASSETS) return "AI is generating 3 concepts...";
    if (status === GenerationStatus.ANALYZING) return "AI Strategist is thinking...";
    return "Processing...";
  }

  const firstError = images.find(img => img.error)?.error;
  const isPermissionError = firstError?.includes('Permission Denied');
  const isGeneratingAnything = status !== GenerationStatus.IDLE && status !== GenerationStatus.COMPLETED && status !== GenerationStatus.ERROR;

  return (
    <div className="min-h-screen pb-20 bg-slate-900">
