export const generateSloganSuggestions = async (audience: string): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a viral marketing expert specializing in Print-on-Demand (POD) and social media trends (TikTok, Google Trends).
      Your task is to generate a list of 5 short, witty, and commercially viable slogans for t-shirts and merchandise.
      The slogans should be tailored to the following target audience: "${audience || 'a general audience with a sense of humor'}".

      Instructions:
      - The slogans must be concise, ideally under 8 words.
      - They should feel fresh, trendy, and highly shareable.
      - Avoid generic or overused phrases.
      - The output must be only a JSON array of strings.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.STRING,
            description: "A witty and short slogan.",
          }
        }
      }
    });
    if (response.text) {
      return JSON.parse(response.text) as string[];
    }
    throw new Error("No slogans generated");
  } catch (error) {
    console.error("Error generating slogan suggestions:", error);
    throw error;
  }
};

