import { GoogleGenAI, Type, VideoGenerationReferenceImage, VideoGenerationReferenceType } from "@google/genai";
import { DesignStrategy, StrategySuggestion, TrendingSlogan } from "../types";
import { NICHES, DESIGN_STYLES, COLOR_PALETTES } from "../constants";

export const generateSloganSuggestions = async (audience: string): Promise<TrendingSlogan[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a viral marketing expert specializing in Print-on-Demand (POD) and social media trends (TikTok, Google Trends).
      Your task is to generate a ranked list of 10 short, witty, and commercially viable slogan trends for t-shirts and merchandise.
      The slogans should be tailored to the following target audience: "${audience || 'a general audience with a sense of humor'}".

      **CRITICAL INSTRUCTIONS:**
      1.  **Language:** All output text ('slogan', 'rationale') MUST be in **Vietnamese**.
      2.  **Grounding:** You MUST use your search tool to find a real, popular, best-selling product online that exemplifies each slogan trend.
      3.  **Product Link:** For each slogan, you MUST provide the direct URL to that product page in the 'productUrl' field. This link must be a real, clickable URL. This is mandatory.
      4.  **Rationale:** The 'rationale' must explain the current trend behind the slogan in Vietnamese.
      5.  **Conciseness:** The slogans must be concise, ideally under 8 words.
      6.  **Format:** The output must be ONLY a JSON array of objects, strictly adhering to the schema.
      `,
      config: {
        tools: [{googleSearch: {}}],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              slogan: { type: Type.STRING, description: "A witty and short slogan, in Vietnamese." },
              rationale: { type: Type.STRING, description: "The marketing trend or rationale behind the slogan, in Vietnamese." },
              productUrl: { type: Type.STRING, description: "A real, best-selling product URL found via search that exemplifies this trend." },
            },
            required: ["slogan", "rationale", "productUrl"]
          }
        }
      }
    });
    if (response.text) {
      return JSON.parse(response.text) as TrendingSlogan[];
    }
    throw new Error("No slogans generated");
  } catch (error) {
    console.error("Error generating slogan suggestions:", error);
    throw error;
  }
};

export const generateFiveDesignConcepts = async (slogan: string, audience: string): Promise<StrategySuggestion[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const nicheOptions = NICHES.map(n => `ID: "${n.id}", Label: "${n.label}"`).join('\n');
    const styleOptions = DESIGN_STYLES.map(s => `ID: "${s.id}", Label: "${s.label}", Context: "${s.context}"`).join('\n');
    const colorOptions = COLOR_PALETTES.map(c => `ID: "${c.id}", Label: "${c.label}", Context: "${c.context}"`).join('\n');

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are an expert Print-on-Demand (POD) market trend analyst and a creative director.
      Your task is to analyze the provided slogan and target audience, then generate the top 3 most commercially viable and distinct design concepts.
      For each concept, you must provide both a high-level strategy and a specific creative direction. All text output must be in **Vietnamese**.

      **Slogan:** "${slogan}"
      **Target Audience:** "${audience || 'General public'}"

      **Available Options (You MUST return one ID from each category for each of the 3 strategies):**

      **Target Niches:**
      ${nicheOptions}

      **Visual Trends:**
      ${styleOptions}

      **Color Palettes:**
      ${colorOptions}

      **Instructions:**
      1.  Analyze the slogan and audience to identify key themes and vibes.
      2.  Cross-reference this with your knowledge of best-selling POD trends.
      3.  Generate an array of 3 unique and diverse concept objects.
      4.  For each object, select the single best ID from the Niches, Visual Trends, and Color Palettes lists.
      5.  Provide a short, catchy 'title' (e.g., "Phong cách Retro Gamer", "Thiền tối giản").
      6.  Provide a brief 'rationale' IN VIETNAMESE explaining why this strategy will sell.
      7.  Crucially, for each object, also provide a detailed 'designStyle' object containing specific creative direction IN VIETNAMESE: 'typography', 'artStyle', 'colors', and 'mood'. This should be detailed enough to guide an image generation AI.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING, description: "A short, catchy title for the strategy, in Vietnamese." },
              nicheId: { type: Type.STRING },
              styleId: { type: Type.STRING },
              colorId: { type: Type.STRING },
              rationale: { type: Type.STRING, description: "Your reasoning for choosing this strategy, citing market trends, in Vietnamese." },
              designStyle: {
                type: Type.OBJECT,
                properties: {
                  typography: { type: Type.STRING },
                  artStyle: { type: Type.STRING },
                  colors: { type: Type.STRING },
                  mood: { type: Type.STRING },
                },
                required: ["typography", "artStyle", "colors", "mood"]
              }
            },
            required: ["title", "nicheId", "styleId", "colorId", "rationale", "designStyle"]
          }
        }
      }
    });

    if (response.text) {
      const suggestions = JSON.parse(response.text) as StrategySuggestion[];
      if (suggestions.length > 3) return suggestions.slice(0, 3);
      return suggestions;
    }
    throw new Error("No strategy suggestion generated");
  } catch (error) {
    console.error("Error suggesting strategies:", error);
    throw error;
  }
};

