export const generateMockupImage = async (prompt: string, referenceImageBase64?: string | null): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const parts: any[] = [{ text: prompt }];
    if (referenceImageBase64) {
      const base64Data = referenceImageBase64.replace(/^data:image\/\w+;base64,/, "");
      parts.push({
        inlineData: { mimeType: 'image/png', data: base64Data }
      });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: parts },
      config: { imageConfig: { aspectRatio: "1:1" } }
    });

    const candidates = response.candidates;
    if (!candidates || candidates.length === 0) throw new Error("No image generated.");

    const imagePart = candidates[0].content.parts.find(p => p.inlineData);
    if (!imagePart?.inlineData?.data) throw new Error("Missing image data.");

    return `data:image/png;base64,${imagePart.inlineData.data}`;
  } catch (error: any) {
    console.error("Error generating image:", error);
    throw error;
  }
};

export const generatePromoVideo = async (slogan: string, strategy: DesignStrategy, referenceImagesBase64: string[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const referenceImagesPayload: VideoGenerationReferenceImage[] = referenceImagesBase64
      .slice(0, 3) // Use up to 3 images as per API limitation
      .map(b64 => ({
        image: {
          imageBytes: b64.replace(/^data:image\/\w+;base64,/, ""),
          mimeType: 'image/png',
        },
        referenceType: VideoGenerationReferenceType.ASSET,
      }));

    if (referenceImagesPayload.length === 0) {
        throw new Error("No valid reference images provided for video generation.");
    }

    const videoCtx = strategy.mockups.video || { music: "upbeat electronic", style: "fast-paced", transitions: "quick cuts" };

    const prompt = `Create a short, dynamic, promotional video for a new product line with the slogan "${slogan}". 
    Video Style: ${videoCtx.style}, with ${videoCtx.transitions}. 
    Music style suggestion: ${videoCtx.music}.
    Showcase the product designs from the reference images in a trendy style suitable for TikTok or YouTube Shorts.`;

    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-generate-preview',
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        referenceImages: referenceImagesPayload,
        resolution: '720p',
        aspectRatio: '9:16' // Vertical for social media
      }
    });

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000)); // Poll every 10 seconds
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) {
      throw new Error("Video generation completed but no download link was found.");
    }

    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    if (!response.ok) {
        throw new Error(`Failed to download video: ${response.statusText}`);
    }
    const blob = await response.blob();
    return URL.createObjectURL(blob);

  } catch (error) {
    console.error("Error generating video:", error);
    throw error;
  }
};

export const generateVideoPrompt = async (
  slogan: string,
  niche: string,
  targetAudience: string,
  strategy: DesignStrategy,
  imageUrls: string[]
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const textPart = {
      text: `
        You are a creative director specializing in viral social media ads for e-commerce brands.
        Your task is to create a detailed video script and shot list for a 15-second promotional video, based on the provided product mockup images. The entire final output script MUST be in **Vietnamese**.

        **Analyze the provided images and follow these instructions:**

        **Brand & Design DNA:**
        - **Slogan:** "${slogan}"
        - **Target Audience:** ${targetAudience || 'General public'}
        - **Niche:** ${niche}
        - **Overall Mood:** ${strategy.designStyle.mood}
        - **Art Style & Colors:** Your description must reflect the visual style and colors present in the attached images.

        **Requirements for the script (in Vietnamese):**
        - **Structure:** Provide a scene-by-scene breakdown (e.g., ### Cảnh 1).
        - **Timestamps:** Suggest approximate timings for each scene (e.g., 0-3s).
        - **Visuals:** Describe the camera shot and action for each scene. **Crucially, your descriptions must be based on the content of the provided mockup images.** For example, instead of "a person wearing a t-shirt", describe the scene from the image: "Một chàng trai trẻ phong cách trên con phố thành thị nhộn nhịp, ánh sáng giờ vàng làm nổi bật chất liệu của chiếc áo phông đen."
        - **On-Screen Text:** Suggest any text overlays. The main slogan should be featured prominently.
        - **Audio:** Suggest a style of trending audio/music and sound effects (e.g., "*vút*," "*tách*").
        - **Output Format:** Use Markdown for clear formatting. The final output should be a complete, ready-to-use prompt in Vietnamese.
      `
    };

    const imageParts = imageUrls.map(url => {
      const base64Data = url.replace(/^data:image\/\w+;base64,/, "");
      return { inlineData: { mimeType: 'image/png', data: base64Data } };
    });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: { parts: [textPart, ...imageParts] },
    });

    if (response.text) {
      return response.text;
    }
    throw new Error("No video prompt generated");
  } catch (error) {
    console.error("Error generating video prompt:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Loader2, Sparkles, Users, BrainCircuit, Palette, Film, Wand2, Lightbulb, X, Link, Copy } from 'lucide-react';
import { generateSloganSuggestions } from '../services/geminiService';
import { TrendingSlogan } from '../types';

interface PromptInputProps {
  onGenerate: (slogan: string, audience: string) => void;
  isGenerating: boolean;
  statusText?: string;
}

const PromptInput: React.FC<PromptInputProps> = ({ 
  onGenerate, 
  isGenerating, 
  statusText,
}) => {
  const [slogan, setSlogan] = useState('');
  const [audience, setAudience] = useState('');
  const [isSuggesting, setIsSuggesting] = useState(false);
  const [sloganSuggestions, setSloganSuggestions] = useState<TrendingSlogan[] | null>(null);
  const [isSloganModalOpen, setIsSloganModalOpen] = useState(false);
  const [copiedLink, setCopiedLink] = useState<string | null>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (slogan.trim()) {
      onGenerate(slogan, audience);
    }
  };

  const handleSuggestSlogan = async () => {
    setIsSuggesting(true);
    setSloganSuggestions(null);
    try {
      const suggestions = await generateSloganSuggestions(audience);
      if (suggestions && suggestions.length > 0) {
        setSloganSuggestions(suggestions);
        setIsSloganModalOpen(true);
      }
    } catch (error) {
      console.error("Failed to suggest slogans:", error);
      alert("Rất tiếc, AI đang bận. Vui lòng thử lại trong giây lát.");
    } finally {
      setIsSuggesting(false);
    }
  };

  const handleSelectSlogan = (selectedSlogan: string) => {
    setSlogan(selectedSlogan);
    setIsSloganModalOpen(false);
  };

  const handleCopyLink = (url: string) => {
    navigator.clipboard.writeText(url);
    setCopiedLink(url);
    setTimeout(() => setCopiedLink(null), 2000);
  };

  return (
    <div className="w-full max-w-5xl mx-auto -mt-6 relative z-10 px-4">
      <form onSubmit={handleSubmit} className="bg-slate-800 p-6 rounded-2xl shadow-2xl border border-slate-700 flex flex-col gap-5">

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Đối tượng mục tiêu?</label>
                <div className="relative">
                    <input
                        type="text"
                        value={audience}
                        onChange={(e) => setAudience(e.target.value)}
                        placeholder="VD: Người yêu mèo, Giáo viên, Gen Z..."
                        className="w-full bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm pl-10"
                        disabled={isGenerating}
                    />
                    <Users className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                </div>
            </div>

            <div className="relative">
                <label className="block text-xs text-slate-400 font-semibold mb-1 ml-1">Slogan / Chữ trên áo</label>
                <div className="relative">
                  <input
                      type="text"
                      value={slogan}
                      onChange={(e) => setSlogan(e.target.value)}
                      placeholder="VD: 'Đi một ngày đàng, học một sàng khôn'"
                      className="w-full bg-slate-900 text-white px-4 py-3 rounded-xl border border-slate-700 focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all text-sm font-medium pr-10"
                      disabled={isGenerating}
                  />
                  <button 
                    type="button" 
                    onClick={handleSuggestSlogan}
                    disabled={isSuggesting || isGenerating}
                    className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 text-slate-400 hover:text-indigo-400 disabled:opacity-50 disabled:cursor-not-allowed transition-colors rounded-md"
                    title="Gợi ý Slogan"
                  >
                    {isSuggesting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Wand2 className="w-4 h-4" />}
                  </button>
                </div>
            </div>
        </div>

        {/* Submit Button */}
        <button
          type="submit"
          disabled={isGenerating || !slogan.trim()}
          className="w-full font-bold px-8 py-4 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2 bg-gradient-to-r from-indigo-600 to-indigo-500 hover:from-indigo-500 hover:to-indigo-400 text-white shadow-indigo-500/30 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {isGenerating ? (
            <>
              <Loader2 className="w-5 h-5 animate-spin" />
              <span>{statusText || 'Đang phân tích chiến lược...'}</span>
            </>
          ) : (
            <>
              <Sparkles className="w-5 h-5" />
              <span>Tạo Thiết kế & Mockup Viral</span>
            </>
          )}
        </button>
      </form>
      <div className="text-center mt-4 text-slate-500 text-xs flex items-center justify-center gap-3">
        <span className="flex items-center gap-1"><BrainCircuit className="w-3 h-3" /> Chiến lược: Gemini 3 Flash</span>
        <span className="flex items-center gap-1"><Palette className="w-3 h-3" /> Ảnh: Gemini Flash Image</span>
        <span className="flex items-center gap-1"><Film className="w-3 h-3" /> Video: Veo</span>
      </div>

      {isSloganModalOpen && sloganSuggestions && (
        <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4 animate-in fade-in duration-300">
          <div className="bg-slate-800 rounded-2xl border border-slate-700 shadow-2xl w-full max-w-3xl flex flex-col max-h-[90vh]">
            <div className="p-4 border-b border-slate-700 flex justify-between items-center">
              <div className='flex items-center gap-2'>
                <Wand2 className="w-5 h-5 text-indigo-400" />
                <h3 className="text-lg font-bold text-white">Top 10 Slogan Bán Chạy Nhất</h3>
              </div>
              <button onClick={() => setIsSloganModalOpen(false)} className="p-1 rounded-full hover:bg-slate-700 transition-colors">
                <X className="w-5 h-5 text-slate-400" />
              </button>
            </div>
            <div className="p-2 sm:p-4 overflow-y-auto">
              <ul className="space-y-3">
                {sloganSuggestions.map((item, index) => (
                  <li key={index}>
                    <div className="w-full text-left p-4 bg-slate-900/50 rounded-lg border border-slate-700/50">
                      <button 
                        onClick={() => handleSelectSlogan(item.slogan)}
                        className="w-full text-left group"
                      >
                        <p className="font-bold text-white text-base group-hover:text-indigo-400 transition-colors">
                          <span className="text-indigo-400 font-black mr-2 text-lg">{index + 1}.</span>
                          {item.slogan}
                        </p>
                      </button>
                      <div className="flex items-start gap-2 mt-2 pl-6">
                        <Lightbulb className="w-4 h-4 text-amber-400/80 flex-shrink-0 mt-0.5" />
                        <p className="text-sm text-slate-400">{item.rationale}</p>
                      </div>
                      <div className="flex items-center justify-between mt-3 pl-6 gap-2">
                          <div className="flex items-center gap-2 truncate flex-1">
                              <Link className="w-4 h-4 text-sky-400/80 flex-shrink-0" />
                              <a href={item.productUrl} target="_blank" rel="noopener noreferrer" className="text-xs text-sky-400 truncate hover:underline" title={item.productUrl}>
                                  {item.productUrl.replace(/^(https?:\/\/)?(www\.)?/, '')}
                              </a>
                          </div>
                          <button onClick={(e) => { e.stopPropagation(); handleCopyLink(item.productUrl); }} className="flex items-center gap-1.5 text-xs text-slate-400 hover:text-white bg-slate-700/50 hover:bg-slate-600 px-2 py-1 rounded-md transition-colors flex-shrink-0">
                              <Copy className="w-3 h-3" />
                              <span>{copiedLink === item.productUrl ? 'Đã chép!' : 'Chép link'}</span>
                          </button>
                      </div>
                    </div>
                  </li>
                ))}
              </ul>
            </div>
            <div className="p-3 border-t border-slate-700 text-center">
              <p className="text-xs text-slate-500">Dựa trên phân tích xu hướng thị trường & mạng xã hội hiện tại.</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PromptInput;

import { GoogleGenAI, Type, VideoGenerationReferenceImage, VideoGenerationReferenceType } from "@google/genai";
import { DesignStrategy, StrategySuggestion, TrendingSlogan } from "../types";
import { NICHES, DESIGN_STYLES, COLOR_PALETTES } from "../constants";

export const generateSloganSuggestions = async (audience: string): Promise<TrendingSlogan[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a viral marketing expert specializing in Print-on-Demand (POD) and social media trends.
      Your task is to generate a ranked list of up to 10 commercially viable slogan trends for the target audience: "${audience || 'a general audience with a sense of humor'}".

      **CRITICAL INSTRUCTIONS:**
      1.  **Language:** The 'slogan' MUST be in **English**. The 'rationale' MUST be in **Vietnamese**.
      2.  **Grounding & Veracity:** You MUST use your search tool to find a real, popular, best-selling product online that exemplifies each slogan trend. For each slogan, you MUST provide the direct, valid, and clickable URL to that product page in the 'productUrl' field. This is mandatory.
      3.  **Strict Filtering:** **If you cannot find a verifiable, real product URL for a trend using your search tool, DO NOT include that trend in the response.** It is absolutely critical that all provided URLs are real and lead to an actual product page. Do not fabricate URLs.
      4.  **Format:** The output must be ONLY a JSON array of objects, strictly adhering to the schema.
      `,
