              <button onClick={() => setIsSloganModalOpen(false)} className="p-1 rounded-full hover:bg-slate-700 transition-colors">
                <X className="w-5 h-5 text-slate-400" />
              </button>
            </div>
            <div className="p-2 sm:p-4 overflow-y-auto">
              <ul className="space-y-3">
