    setIsSuggesting(true);
    setSloganSuggestions(null);
    try {
      const suggestions = await generateSloganSuggestions(audience);
      if (suggestions && suggestions.length > 0) {
        setSloganSuggestions(suggestions);
        setIsSloganModalOpen(true);
      }
    } catch (error) {
      console.error("Failed to suggest slogans:", error);
      alert("Sorry, the AI muse is busy. Please try again in a moment.");
    } finally {
      setIsSuggesting(false);
    }
  };

  const handleSelectSlogan = (selectedSlogan: string) => {
    setSlogan(selectedSlogan);
    setIsSloganModalOpen(false);
  };

  const handleCopyLink = (url: string) => {
    navigator.clipboard.writeText(url);
    setCopiedLink(url);
    setTimeout(() => setCopiedLink(null), 2000);
  };

