 mb-2"> <h4 className="font-bold text-white">Tags / Keywords</h4> <button onClick={() => handleCopySection(productListing.tags.join(', '), 'tags')} className="flex items-center gap-1.5 text-xs text-slate-400 hover:text-white bg-slate-700/50 hover:bg-slate-600 px-2 py-1 rounded-md transition-colors"> <Clipboard className="w-3 h-3" /> {copiedSection === 'tags' ? 'Copied!' : 'Copy as CSV'} </button> </div> <div className="p-3 bg-slate-900/50 rounded-lg border border-slate-700 flex flex-wrap gap-2"> {productListing.tags.map((tag, index) => ( <span key={index} className="bg-slate-700 text-slate-300 text-xs font-medium px-2.5 py-1 rounded-full">{tag}</span> ))} </div> </div> </div> <div className="p-4 border-t border-slate-700 flex justify-end"> <button onClick={() => setIsListingModalOpen(false)} className="px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-lg transition-all text-sm shadow-lg shadow-indigo-500/30">Close</button> </div> </div> </div> )}
    </div>
  );
};

